ARTICLES = [
    # HR Policies (20)
    ("HR Policies", "Employee Leave Policy 2024",
     "This policy outlines the various types of leave available to employees including annual, sick, and emergency leave. All employees are entitled to 20 days of annual leave per year, accruing at 1.67 days per month. Leave requests must be submitted at least 48 hours in advance through the HR portal.\n\nSick leave is granted for up to 10 days per year with a medical certificate required for absences exceeding 3 consecutive days. Emergency leave of up to 5 days may be granted for immediate family bereavement or critical personal situations requiring management approval.\n\nUnused annual leave can be carried over to the next year up to a maximum of 10 days. Any leave balance remaining beyond this limit will be forfeited at the year end. Employees leaving the organization will be compensated for unused leave up to the carry-over limit.",
     "Comprehensive guide to employee leave entitlements including annual, sick, and emergency leave policies.",
     "hr,policy,leave,employee benefits"),
    ("HR Policies", "Remote Work Guidelines",
     "Remote work arrangements allow employees to work from locations outside the primary office, supporting flexibility and work-life balance. Employees must maintain the same productivity standards and availability during core business hours (9 AM to 3 PM local time) when working remotely.\n\nAll remote workers must have a dedicated workspace with a reliable internet connection of at least 25 Mbps. Company-issued equipment must be used for all work activities and must be kept secure at all times. Personal devices may only be used with prior IT security approval and VPN configuration.\n\nRemote work eligibility is reviewed quarterly by direct managers based on role requirements and performance metrics. Employees on a performance improvement plan are not eligible for remote work. All remote work agreements must be formally documented and renewed annually.",
     "Guidelines for employees working remotely including connectivity requirements, security standards, and eligibility criteria.",
     "remote work,flexibility,policy,guidelines"),
    ("HR Policies", "Performance Review Process",
     "The annual performance review process is designed to recognize achievements, identify development areas, and align individual goals with organizational objectives. Reviews are conducted bi-annually in June and December with a self-assessment component completed by the employee prior to the manager review.\n\nEach review covers five core competency areas: job knowledge, communication, teamwork, initiative, and results delivery. Ratings range from 1 (Does Not Meet Expectations) to 5 (Consistently Exceeds Expectations). A minimum rating of 3 is required to be eligible for merit increases.\n\nFollowing the review, a personalized development plan is created collaboratively by the employee and manager. This plan includes at least two SMART goals for the next review period and any required training or mentorship support. HR Business Partners are available to mediate disputes or provide guidance on the review process.",
     "Overview of the bi-annual employee performance review process including competency ratings and development planning.",
     "performance,review,goals,development"),
    ("HR Policies", "Code of Conduct Policy",
     "The Code of Conduct establishes the standards of professional behavior expected from all employees, contractors, and business partners. Every individual representing the organization must act with integrity, respect, and accountability in all professional interactions.\n\nProhibited conduct includes harassment of any kind, discrimination based on protected characteristics, misuse of company resources, conflicts of interest not disclosed to management, and any form of retaliation against employees who report concerns in good faith.\n\nViolations of the Code of Conduct are investigated by HR in coordination with Legal and may result in disciplinary action up to and including termination. Employees are encouraged to report concerns through the anonymous ethics hotline or directly to their HR Business Partner. All reports are treated with confidentiality to the extent permitted by law.",
     "Standards of professional behavior and ethical conduct expected from all employees and business partners.",
     "ethics,conduct,policy,compliance"),
    ("HR Policies", "Harassment Prevention Policy",
     "The organization maintains a zero-tolerance policy toward harassment in any form, including verbal, physical, visual, and digital harassment. This policy applies to all interactions in the workplace, at company events, and in any business-related communications regardless of medium.\n\nHarassment includes unwelcome comments about personal characteristics, offensive jokes, intimidation, exclusion from professional opportunities, and any conduct that creates a hostile work environment. Sexual harassment specifically includes unwanted advances, requests for favors, and any conduct of a sexual nature that interferes with an individual's work performance.\n\nAll harassment complaints are investigated within 10 business days by a designated HR investigator. Both parties receive a written outcome and have the right to appeal the decision within 5 business days. The organization provides annual training on harassment prevention to all employees and managers.",
     "Zero-tolerance policy against all forms of workplace harassment with complaint procedures and investigation timelines.",
     "harassment,policy,workplace safety,compliance"),
    ("HR Policies", "New Employee Onboarding Checklist",
     "The onboarding process ensures new employees are set up for success from their first day. Prior to the start date, IT prepares system access, equipment, and software licenses. The hiring manager designates a buddy to provide peer support and cultural integration assistance during the first 30 days.\n\nDuring the first week, new employees complete mandatory compliance training, meet with HR to review benefits and policies, and attend department orientation sessions. System access to all required platforms should be fully configured by end of day one. New employees are enrolled in a 90-day structured onboarding program.\n\nAt the 30-day mark, the manager conducts a check-in meeting to address questions and provide initial feedback. At 60 days, a more formal progress review is held. The 90-day meeting serves as a milestone review where role fit, performance expectations, and development goals are formally established.",
     "Step-by-step onboarding checklist for new employees covering the first 90 days from pre-start setup to milestone reviews.",
     "onboarding,new employee,checklist,orientation"),
    ("HR Policies", "Benefits Enrollment Guide",
     "Employees are eligible to enroll in company benefits within 30 days of their hire date or during the annual open enrollment period in November. Benefits include medical, dental, vision, life insurance, disability coverage, and retirement savings plans.\n\nMedical coverage is available through three plan tiers: Basic, Standard, and Premium. The company contributes 80% of the Premium tier cost for employee-only coverage. Dependent coverage is available at additional cost with the company contributing 50% of the Premium tier rate for one dependent.\n\nRetirement savings through the 401(k) plan include a company match of up to 4% of annual salary when employees contribute a minimum of 4%. Vesting of company contributions follows a 3-year graded schedule. Employees can modify their contribution percentage at any time through the HR portal with changes taking effect the following pay period.",
     "Guide to enrolling in company benefits including medical, dental, retirement savings, and insurance options.",
     "benefits,enrollment,insurance,retirement"),
    ("HR Policies", "Disciplinary Action Procedure",
     "The disciplinary process is designed to be fair, consistent, and corrective rather than punitive. The process generally follows a progressive discipline model: verbal warning, written warning, final warning, and termination. However, severe violations may bypass earlier steps depending on the nature of the conduct.\n\nA verbal warning is documented in the employee file and remains active for 6 months. Written warnings are issued for repeated violations or more serious first offenses and remain active for 12 months. A final warning is issued when prior corrective measures have not produced lasting improvement and carries a 24-month active period.\n\nAll disciplinary actions are reviewed by HR before issuance to ensure consistency and legal compliance. Employees have the right to respond to disciplinary notices within 5 business days. Appeals can be submitted to the HR Director within 10 business days of receiving a written or final warning.",
     "Progressive discipline procedure covering verbal warnings, written warnings, final warnings, and termination guidelines.",
     "discipline,hr policy,performance,procedure"),
    ("HR Policies", "Business Travel Policy",
     "Business travel must be pre-approved by the employee's manager and submitted through the travel management system at least 5 business days prior to departure. Economy class is the standard for flights under 6 hours; business class may be approved for flights over 6 hours with executive approval.\n\nHotel accommodations are reimbursed up to a maximum nightly rate based on the destination city tier. Employees should book accommodations through the preferred hotel partners to receive negotiated rates. Meals are reimbursed at a per diem rate of $50 domestic and $75 international per day, inclusive of tips.\n\nExpense reports must be submitted within 15 business days of returning from travel with original receipts for all items over $25. Non-reimbursable expenses include personal entertainment, alcohol, minibar charges, and travel insurance purchased outside the corporate plan. Personal travel combined with business trips must be clearly separated in expense reporting.",
     "Comprehensive business travel policy covering booking procedures, expense limits, and reimbursement guidelines.",
     "travel,expense,reimbursement,policy"),
    ("HR Policies", "Workplace Safety Guidelines",
     "Maintaining a safe workplace is a shared responsibility between the organization and all employees. All staff must complete annual workplace safety training and are required to report any unsafe conditions, near-misses, or injuries to their supervisor and the Safety team immediately.\n\nEmergency evacuation routes are posted throughout all facilities and must be kept clear at all times. Designated assembly points are marked in each building and all employees must be familiar with their nearest exit route. Emergency response drills are conducted semi-annually for all locations.\n\nErgonomic assessments are available to all employees and are mandatory for those experiencing work-related discomfort. Adjustable workstations, ergonomic peripherals, and standing desk options are available through facilities upon manager approval. Any workplace injury requiring medical treatment must be documented on an incident report within 24 hours.",
     "Workplace safety standards including emergency procedures, ergonomic guidelines, and incident reporting requirements.",
     "safety,ergonomics,policy,workplace"),
    ("HR Policies", "Dress Code Policy",
     "The organization maintains a business casual dress code for in-office and client-facing work. Business casual includes items such as collared shirts, blouses, slacks, skirts, and closed-toe shoes. Jeans are acceptable on Fridays and during remote work days unless client meetings are scheduled.\n\nFormal business attire is required for executive presentations, board meetings, and formal client engagements. Employees are notified in advance when formal attire is expected. Branded company attire may be worn on team event days and is encouraged at industry conferences where provided.\n\nAttire that is not permitted includes clothing with offensive graphics or language, overly casual items such as athletic wear or beachwear, and clothing that does not meet basic hygiene standards. Managers may counsel employees privately on dress code compliance, and repeated violations may result in disciplinary action.",
     "Business casual dress code guidelines covering daily wear, formal occasions, and restricted attire.",
     "dress code,policy,workplace,appearance"),
    ("HR Policies", "Employee Referral Program Guide",
     "The Employee Referral Program rewards employees for helping the organization attract qualified candidates. Employees can submit referrals for any open position through the HR portal by providing the candidate's resume and contact information along with a brief description of the candidate's qualifications.\n\nReferral bonuses are paid in two installments: 50% upon the referred candidate's start date and 50% after 6 months of continuous employment. Bonus amounts range from $500 to $3,000 depending on the role level. Senior and specialized technical positions carry the highest bonus tiers.\n\nEmployees are not eligible to refer direct reports, family members, or individuals with whom they have a personal financial relationship. HR verifies eligibility before processing any bonus payment. Multiple employees referring the same candidate are credited to the first verifiable submission.",
     "Guide to participating in the employee referral program including bonus structures and eligibility requirements.",
     "referral,hiring,bonus,hr program"),
    ("HR Policies", "Exit Interview Process",
     "Exit interviews are conducted with all voluntary departing employees to gather candid feedback on their experience and identify areas for organizational improvement. The interview is typically held during the employee's final week and is conducted by an HR Business Partner rather than the departing employee's direct manager.\n\nInterviews cover topics including reasons for departure, management experience, team dynamics, career development opportunities, and overall job satisfaction. Responses are recorded anonymously in aggregate reports shared with senior leadership quarterly. Individual responses are not shared with managers or business units.\n\nFollowing the exit interview, HR coordinates a knowledge transfer plan with the departing employee and their manager. System access is revoked on the final day of employment. Exit interviews are mandatory for all employees on standard notice periods and optional for those on immediate separation agreements.",
     "Process for conducting exit interviews to gather departure feedback and manage knowledge transfer before an employee's last day.",
     "exit interview,offboarding,feedback,hr"),
    ("HR Policies", "Maternity and Paternity Leave Policy",
     "The organization provides generous parental leave to support employees during the significant life event of welcoming a new child. Primary caregivers are entitled to 16 weeks of paid leave, while secondary caregivers receive 4 weeks of paid leave. Leave must begin within 12 months of the child's birth, adoption, or foster placement.\n\nEmployees must notify HR and their manager at least 8 weeks before the anticipated leave start date. For birth parents, medical certification is required within 2 weeks of delivery. Documentation for adoption or foster placements must be submitted upon approval or placement.\n\nReturn-to-work arrangements are discussed 4 weeks before the scheduled return date. Employees may request a phased return with reduced hours for the first 4 weeks at full pay. All employees returning from parental leave are guaranteed reinstatement to their original role or an equivalent position at the same compensation level.",
     "Parental leave entitlements for primary and secondary caregivers with notification requirements and return-to-work support.",
     "parental leave,maternity,paternity,policy"),
    ("HR Policies", "Training Budget Policy",
     "Each employee is allocated an annual training budget to support ongoing professional development. The budget varies by role level: individual contributors receive $1,000, managers receive $2,000, and directors and above receive $3,500. Unused budgets do not carry over to the following year.\n\nEligible expenses include conference registrations, online courses, professional certifications, and relevant books or learning materials. All training spend must be approved by the employee's manager and submitted through the Learning Management System before enrollment. Training directly related to the employee's current role or development plan is prioritized.\n\nFor external certifications where the total cost exceeds $2,000, employees may apply for supplemental funding through the HR Training Fund. Applications are reviewed quarterly. A training bond of 12 months applies to company-funded certifications costing over $5,000; employees who leave before completing the bond period must repay a pro-rated amount.",
     "Annual training budget allocations by role level with eligible expenses and supplemental funding application process.",
     "training,budget,professional development,policy"),
    ("HR Policies", "Promotion Criteria and Process",
     "Promotions recognize employees who consistently demonstrate exceptional performance, leadership, and readiness for increased responsibility. Eligibility is assessed during mid-year and year-end performance cycles. Employees must have been in their current role for at least 12 months and achieved a minimum performance rating of 4 in their most recent review.\n\nPromotion nominations are submitted by managers to the HR Business Partner with supporting evidence including accomplishments, competency examples, and a business case for the role change. Nominations are reviewed by a cross-functional Promotion Committee that ensures consistency and fairness across departments.\n\nApproved promotions take effect at the start of the next fiscal quarter with corresponding compensation adjustments. Employees are notified in writing by HR and receive an updated job description and goal framework. Promotions are celebrated publicly within the team and recognized in the company's internal communications newsletter.",
     "Criteria and process for employee promotions including eligibility requirements, nomination procedure, and recognition.",
     "promotion,career growth,performance,hr"),
    ("HR Policies", "Attendance and Punctuality Policy",
     "Regular attendance and punctuality are critical to team productivity and client service delivery. Employees are expected to be at their workstation or available for remote work at their scheduled start time. Late arrivals of more than 15 minutes must be communicated to the manager before the start time.\n\nAbsences must be reported before the start of the workday through the HR portal or by direct notification to the manager. Unplanned absences exceeding 3 consecutive days require medical documentation. Patterns of recurring absences or late arrivals, even when individually excused, may be addressed through the performance improvement process.\n\nFlex-time arrangements allow employees to adjust their standard 8-hour workday within a core hours window (10 AM to 3 PM). Flex arrangements must be approved by the manager and reviewed quarterly. Time off in lieu for approved overtime is accrued at a 1:1 ratio and must be used within the same quarter.",
     "Attendance and punctuality standards including reporting procedures, flex-time rules, and absence documentation requirements.",
     "attendance,punctuality,policy,hr"),
    ("HR Policies", "Background Check Policy",
     "Pre-employment background checks are conducted for all new hires and applicable contractors prior to their start date. Checks cover criminal history, employment verification for the past 7 years, and education credential verification. Roles in finance, IT security, and executive leadership also require a credit check.\n\nBackground checks are conducted by a third-party screening partner in compliance with applicable employment laws. Candidates must provide written consent before any check is initiated. Results are reviewed by HR and the hiring manager; findings are evaluated in context of the role and the nature of any identified issues.\n\nAdverse findings do not automatically disqualify a candidate. HR conducts an individualized assessment considering the nature of the finding, elapsed time, and relevance to the role. Candidates are notified of adverse findings and given the opportunity to dispute inaccurate information through the screening provider before a final decision is made.",
     "Pre-employment background check procedures including scope, consent requirements, and adverse finding review process.",
     "background check,hiring,compliance,screening"),
    ("HR Policies", "Confidentiality Agreement Guide",
     "All employees are required to sign a Confidentiality and Non-Disclosure Agreement as a condition of employment. The agreement covers proprietary information, trade secrets, client data, financial information, and strategic plans that are not publicly available.\n\nConfidential information must not be disclosed to unauthorized internal or external parties, must not be used for personal benefit, and must be stored and transmitted only through approved company systems. Physical documents containing confidential information must be stored in locked cabinets when not in use and shredded using approved destruction methods when no longer needed.\n\nThe confidentiality obligations continue for a period of 2 years following the termination of employment. Breaches of confidentiality are treated as serious misconduct and may result in immediate termination and legal action. Employees with questions about whether specific information is confidential should consult their manager or Legal before disclosing.",
     "Guide to confidentiality obligations covering scope of protected information, storage requirements, and post-employment obligations.",
     "confidentiality,nda,compliance,policy"),
    ("HR Policies", "Team Building Policy",
     "Team building activities are funded by the department budget and organized on a quarterly basis to strengthen collaboration, morale, and cross-functional relationships. Each team is allocated $75 per employee per quarter for team building events, with larger cross-department initiatives funded separately through the HR Engagement budget.\n\nActivities should be inclusive and accessible to all team members regardless of physical ability, dietary needs, or personal beliefs. Proposed activities must be submitted to the HR Events Coordinator at least 3 weeks in advance for review and coordination. Alcohol-inclusive events require explicit manager approval and must include non-alcoholic alternatives.\n\nParticipation in team building activities is voluntary. Employees who cannot attend due to personal circumstances should not be penalized. Virtual equivalents must be offered for any in-person event to accommodate remote team members. Post-event feedback forms are collected to improve future planning.",
     "Policy and budget guidelines for organizing inclusive, accessible team building activities on a quarterly basis.",
     "team building,culture,engagement,policy"),

    # IT Support (20)
    ("IT Support", "Password Reset Step by Step",
     "Resetting your account password is a straightforward self-service process available through the IT portal. If you have forgotten your current password, navigate to the login page and click 'Forgot Password.' A reset link will be sent to your registered email address and is valid for 15 minutes.\n\nIf your account is locked due to repeated failed login attempts, please submit a ticket through the IT Help Desk portal or call the support line. Account lockouts are automatically released after 30 minutes; however, IT can expedite the process during business hours. You will be prompted to verify your identity through multi-factor authentication before regaining access.\n\nWhen creating a new password, it must be at least 12 characters long and include uppercase letters, lowercase letters, numbers, and one special character. Passwords cannot contain your name, email address, or any of your last 10 passwords. Password expiry is set to every 90 days; you will be reminded 14 days before expiry.",
     "Step-by-step self-service guide for resetting forgotten passwords and unlocking locked accounts.",
     "password,reset,account,it support"),
    ("IT Support", "VPN Setup and Configuration Guide",
     "The corporate VPN provides secure access to internal systems and resources when working outside the office network. Download the Cisco AnyConnect client from the IT software portal and install it on your company-issued device. Personal devices must be approved by IT Security before VPN installation.\n\nTo connect, open the AnyConnect client and enter the VPN server address provided in your onboarding documentation. Authenticate using your Active Directory credentials followed by the one-time code from your authenticator app. The connection timeout is set to 8 hours; you will need to re-authenticate after that period.\n\nIf you experience connection issues, ensure your device has the latest OS updates installed and that your firewall is not blocking the VPN client. Port 443 and 1194 must be open for VPN traffic. For persistent issues, submit a ticket with your error message and the diagnostic log exported from the AnyConnect client.",
     "Installation and configuration guide for the corporate VPN client with troubleshooting steps for common connection issues.",
     "vpn,remote access,security,configuration"),
    ("IT Support", "Software Installation Request Process",
     "All software installations on company devices must be requested and approved through the IT Service Management portal. Unauthorized software installations are prohibited and may trigger security alerts. Navigate to the portal, select 'Software Request,' and choose from the approved software catalog.\n\nIf the required software is not in the approved catalog, submit a custom request with the software name, version, vendor, business justification, and cost estimate. Custom requests are reviewed by IT Security within 5 business days for security assessment and compatibility testing. Approval also requires sign-off from the requestor's manager.\n\nOnce approved, standard catalog software is deployed automatically to your device within 24 hours. Custom software installations are scheduled by an IT technician during a maintenance window. You will be notified via email when the software is ready. Emergency software requests for business-critical needs can be flagged for same-day processing.",
     "Process for requesting and obtaining approval for software installations on company-managed devices.",
     "software,installation,it request,approval"),
    ("IT Support", "Hardware Replacement Procedure",
     "Hardware replacement requests are initiated when existing equipment becomes faulty, obsolete, or no longer meets the technical requirements of the role. Submit a request through the IT Hardware portal, describing the issue in detail and attaching any relevant error messages or diagnostic outputs.\n\nIT will assess the request within 3 business days. If the device is under warranty, IT will coordinate with the vendor for repair or replacement. Non-warranty devices are evaluated against the hardware refresh schedule; devices older than 4 years are typically approved for replacement. Loaner devices are available for urgent situations while repairs are in progress.\n\nWhen new hardware is issued, IT will migrate your data and application settings from the old device when feasible. Users are responsible for ensuring their critical data is backed up to OneDrive or the network share prior to the hardware swap. Old devices must be returned to IT within 5 business days for secure data wiping and asset decommission.",
     "Procedure for requesting hardware replacement including assessment criteria, loaner availability, and data migration support.",
     "hardware,replacement,it,equipment"),
    ("IT Support", "Email Client Configuration Guide",
     "The corporate email platform uses Microsoft Exchange with Outlook as the primary desktop and mobile client. New accounts are automatically provisioned within 24 hours of onboarding completion and credentials are delivered via the secure onboarding portal.\n\nTo configure Outlook on your desktop, open the application and enter your corporate email address. Autodiscover will automatically populate the server settings. If autodiscover fails, manually enter the Exchange server address from the IT configuration reference sheet. Ensure your client version is Outlook 2019 or later for full feature compatibility.\n\nFor mobile configuration, download Outlook from the App Store or Google Play and sign in with your corporate credentials. Enroll the device in Mobile Device Management (MDM) when prompted; this is mandatory for corporate email access on personal devices. If you experience sync issues or missing folders, try rebuilding the Outlook profile from Control Panel or contact the Help Desk.",
     "Step-by-step configuration guide for Microsoft Outlook desktop and mobile clients with troubleshooting tips.",
     "email,outlook,configuration,it support"),
    ("IT Support", "Network Connectivity Troubleshooting",
     "Network issues can range from complete connectivity loss to slow performance or intermittent drops. Before escalating to IT, perform these self-service diagnostic steps. First, check if other devices on the same network are experiencing issues to determine if it is device-specific or network-wide.\n\nRestart your device and the network adapter by disabling and re-enabling it from Network Settings. Run the built-in Windows Network Diagnostics tool, which can automatically detect and resolve common issues. Check whether your IP address is correctly assigned by running 'ipconfig' in Command Prompt; if it shows a 169.x.x.x address, there is a DHCP issue.\n\nIf the above steps do not resolve the issue, collect a network trace using the IT-provided diagnostic tool and submit it with your Help Desk ticket. Include details of the issue, affected time period, and any error messages. IT network engineers monitor critical infrastructure 24/7 and will prioritize outages affecting multiple users.",
     "Self-service troubleshooting guide for common network connectivity issues with escalation steps for unresolved problems.",
     "network,troubleshooting,connectivity,it support"),
    ("IT Support", "Remote Desktop Access Setup",
     "Remote Desktop Protocol (RDP) allows you to access your office workstation from any approved device. Remote Desktop must be enabled on the target machine by IT before first use; submit a request through the IT portal at least 2 business days before you need remote access.\n\nTo connect from Windows, open Remote Desktop Connection and enter the hostname or IP address of your office machine. Use your Active Directory credentials to authenticate. The connection is tunneled through the corporate VPN, so you must connect to VPN first before initiating the RDP session.\n\nFor Mac users, download the Microsoft Remote Desktop app from the Mac App Store. iOS and Android users can use the Microsoft Remote Desktop mobile app. All remote desktop sessions are logged and monitored by IT Security. Sessions idle for more than 30 minutes are automatically disconnected for security. Contact the Help Desk if you encounter certificate errors or persistent authentication failures.",
     "Setup and usage guide for Remote Desktop Protocol access to office workstations with VPN pre-requisites and troubleshooting.",
     "remote desktop,rdp,access,it setup"),
    ("IT Support", "Office Printer Configuration Guide",
     "Office printers are available on the corporate print server and can be added to your workstation without IT assistance. Open Settings, navigate to Printers and Scanners, click 'Add a Printer or Scanner,' and select your nearest printer from the list. If the printer is not visible, search by the printer hostname found on the IT asset label attached to each device.\n\nFor secure printing, all jobs are held in a queue until you authenticate at the printer with your employee badge or PIN. This prevents sensitive documents from being left unattended in the output tray. To release your print job, tap your badge on the printer reader or enter your PIN on the control panel.\n\nIf you encounter printing errors, check that the printer is online and not showing any error lights. Clear the print queue from your Printers and Scanners settings if jobs are stuck. For paper jams, follow the instructions on the printer's control panel. Driver issues can be resolved by uninstalling and reinstalling the printer driver from the IT software catalog.",
     "Guide to adding office printers, using secure print release, and troubleshooting common printing errors.",
     "printer,configuration,printing,it support"),
    ("IT Support", "Two Factor Authentication Setup",
     "Two-Factor Authentication (2FA) is mandatory for all corporate accounts and adds a critical second layer of security beyond your password. You will be prompted to set up 2FA during initial account activation. Download the Microsoft Authenticator app from your device's app store to begin.\n\nOpen the Authenticator app and select 'Add Account' then 'Work or School Account.' Scan the QR code displayed in the account setup portal, or manually enter the provided key. Once configured, you will receive a 6-digit time-based code that refreshes every 30 seconds. Enter this code along with your password when prompted during login.\n\nIf you change phones or lose access to your authenticator app, contact the IT Help Desk immediately to initiate an account recovery process. Emergency backup codes are provided during initial setup and should be stored securely offline. Do not share your authentication codes with anyone, including IT staff — legitimate IT support will never ask for your 2FA code.",
     "Step-by-step guide to setting up and using Two-Factor Authentication for all corporate accounts.",
     "2fa,authentication,security,it setup"),
    ("IT Support", "Data Backup and Recovery Procedure",
     "All work data must be stored in approved locations to ensure it is backed up automatically. Company-approved storage includes OneDrive for Business for personal files, SharePoint for team collaboration, and designated network shares for departmental data. Local drive storage on workstations is not backed up and should only be used for temporary working files.\n\nAutomated backups run daily at 11 PM for all approved storage locations. Backups are retained for 90 days for document libraries and 30 days for email. Version history is enabled on OneDrive and SharePoint, allowing you to restore previous versions of files up to 180 days.\n\nTo request a file recovery, submit a ticket through the IT portal specifying the file path, last known good date, and reason for recovery. IT will process recovery requests within 2 business hours for critical business data and 1 business day for standard requests. Users are responsible for reporting data loss immediately; delayed reporting reduces the likelihood of successful recovery.",
     "Guidelines for approved data storage locations, automatic backup schedules, and the process for requesting file recovery.",
     "backup,recovery,data,storage"),
    ("IT Support", "Antivirus and Malware Policy",
     "All company-managed devices are protected by Crowdstrike endpoint protection, which provides real-time threat detection and automated response. The agent is pre-installed on all devices during provisioning and must not be disabled or tampered with. Disabling endpoint protection is treated as a security violation.\n\nIf the endpoint agent detects a threat, it will automatically quarantine the affected file and alert the IT Security team. You may receive a notification on your device; do not attempt to restore quarantined files without IT Security guidance. Suspicious emails, unexpected pop-ups, or unusual system behavior should be reported immediately to security@company.com.\n\nPersonal devices used to access corporate resources through an approved BYOD program must also have an approved antivirus solution installed. Quarterly compliance scans are run on all devices to verify protection status. Devices found to be non-compliant are disconnected from the corporate network until remediation is complete.",
     "Endpoint protection policy covering the antivirus tool in use, automated threat responses, and compliance requirements for all devices.",
     "antivirus,malware,security,policy"),
    ("IT Support", "Security Incident Response Guide",
     "A security incident is any event that threatens the confidentiality, integrity, or availability of company information or systems. Incidents include unauthorized access, data breaches, ransomware, phishing attacks, and accidental data disclosure. All incidents must be reported to the IT Security team within 1 hour of discovery.\n\nTo report an incident, call the IT Security hotline (available 24/7) or email security@company.com with a description of what occurred, when it was first noticed, what systems are affected, and any actions already taken. Do not attempt to investigate or remediate a potential breach without IT Security guidance, as this may destroy forensic evidence.\n\nThe IT Security team will classify the incident by severity, contain the threat, conduct a forensic investigation, and restore affected systems. A post-incident report is completed within 5 business days and shared with senior leadership. Lessons learned are incorporated into security awareness training updates.",
     "Incident response guide covering how to identify, report, and support investigation of security incidents affecting company systems.",
     "security incident,response,reporting,it security"),
    ("IT Support", "Browser Compatibility Standards",
     "The organization supports specific browsers for accessing corporate web applications to ensure security, performance, and consistent user experience. Approved browsers are Google Chrome (latest stable version), Microsoft Edge (Chromium-based, latest stable), and Mozilla Firefox ESR for legacy application compatibility.\n\nBrowsers must be kept up to date through automatic updates, which are centrally managed by IT on company devices. Disabling browser updates is not permitted. Legacy Internet Explorer is no longer supported and access to corporate applications is blocked from IE. Employees are encouraged to migrate any personal bookmarks to approved browsers.\n\nBrowser extensions must be limited to those from the approved extensions catalog available in the IT portal. Unauthorized extensions may capture credentials or inject malicious code and are automatically blocked by corporate policy. If you require an extension for legitimate business use, submit an exception request with a business justification for IT Security review.",
     "Browser compatibility standards covering approved browsers, update requirements, and extension management policy.",
     "browser,compatibility,it standards,security"),
    ("IT Support", "Mobile Device Management Policy",
     "Mobile Device Management (MDM) enrollment is required for any mobile device used to access corporate email, applications, or data. Company-issued devices are automatically enrolled during provisioning. Personal devices must be enrolled through the self-service IT portal before accessing any corporate resources.\n\nMDM enrollment installs a management profile that allows IT to enforce security policies including screen lock, encryption, and remote wipe. The management profile does not have access to personal apps, photos, or messages on personal devices. Separation of corporate and personal data is maintained through containerization technology.\n\nIn the event of a lost or stolen device, immediately report it to IT Security to initiate a remote wipe of corporate data. Device wipe commands are sent within 30 minutes of a verified report. Enrollment must be renewed annually and devices that have not checked in for 90 days are automatically unenrolled and access to corporate resources is revoked.",
     "Policy for enrolling company and personal mobile devices in MDM to enforce security standards and enable remote management.",
     "mobile device,mdm,security,policy"),
    ("IT Support", "Cloud Storage Usage Guide",
     "The company provides OneDrive for Business as the primary cloud storage platform for individual file storage, with SharePoint Online for team and project collaboration. Each employee receives 1TB of OneDrive storage and access to team SharePoint sites based on their departmental assignments.\n\nFiles shared externally must use the OneDrive or SharePoint sharing features with time-limited links rather than personal consumer cloud services. External sharing of files classified as Confidential or above requires manager approval. Unapproved cloud storage tools such as Dropbox, Google Drive, or iCloud are not sanctioned for corporate data.\n\nFiles stored in OneDrive and SharePoint are automatically versioned and backed up. Large file transfers to cloud storage should be scheduled during off-peak hours to avoid impacting network performance. Storage usage reports are reviewed quarterly; employees consistently exceeding 80% of their quota will be contacted by IT to archive older files.",
     "Guide to using OneDrive and SharePoint for corporate file storage with external sharing guidelines and prohibited services.",
     "cloud storage,onedrive,sharepoint,it policy"),
    ("IT Support", "IT Asset Lifecycle Management",
     "IT assets including hardware and licensed software are tracked throughout their lifecycle from procurement to decommission. All assets are tagged with a barcode label upon receipt and registered in the IT Asset Management system. Employees are responsible for the safekeeping of assets assigned to them.\n\nHardware refresh cycles are: laptops every 4 years, desktops every 5 years, monitors every 7 years, and mobile devices every 3 years. Assets approaching end-of-lifecycle are proactively identified during the annual budget cycle and replacement is planned accordingly. Employees may request early refresh if the device is causing significant productivity impact.\n\nUpon separation from the company, all IT assets must be returned to the IT department within 5 business days. Assets are subject to a secure data wiping process before being refurbished, donated, or disposed of in compliance with environmental regulations. Employees found to have lost or damaged assigned assets through negligence may be subject to financial recovery.",
     "IT asset lifecycle management covering hardware tagging, refresh cycles, and decommission procedures.",
     "it assets,lifecycle,hardware,policy"),
    ("IT Support", "Help Desk Ticket Submission Guide",
     "The IT Help Desk is the single point of contact for all technology support needs. Tickets can be submitted through the self-service portal, by email to helpdesk@company.com, or by phone during business hours (8 AM to 6 PM). For critical outages affecting business operations, use the phone line for the fastest response.\n\nWhen submitting a ticket, include the device name (found on the IT asset label), operating system version, a detailed description of the issue, and any error messages. Screenshots or video recordings of the issue significantly speed up resolution. Indicate the business impact and urgency level to help IT prioritize correctly.\n\nTickets are categorized as P1 (Critical — business down), P2 (High — significant impact), P3 (Medium — limited impact), or P4 (Low — cosmetic/informational). Target response times are: P1: 1 hour, P2: 4 hours, P3: 1 business day, P4: 3 business days. You can track ticket status and add comments through the portal.",
     "Guide to submitting IT Help Desk tickets with priority levels, required information, and target response times.",
     "help desk,it support,ticket,troubleshooting"),
    ("IT Support", "System Access Request Procedure",
     "Access to corporate systems, applications, and shared drives must be formally requested and approved before it is provisioned. Submit an access request through the Identity and Access Management portal specifying the system, access level required (read-only, read-write, admin), and the business justification.\n\nAccess requests require approval from the requester's manager and the system owner. Role-based access templates are available for common job functions and can streamline the request for new hires or role changes. All access is granted based on the principle of least privilege — the minimum access necessary to perform the job function.\n\nAccess reviews are conducted semi-annually to identify and revoke stale or excess permissions. Employees who change roles must submit a new access request for their new responsibilities; previous role access will be revoked within 5 business days of the role change. Access for contractors and vendors is always time-bound and expires automatically.",
     "Procedure for requesting access to corporate systems with approval workflow, least-privilege principles, and access review schedule.",
     "access,permissions,security,it request"),
    ("IT Support", "Software License Management Policy",
     "Software licenses are a significant cost and compliance obligation for the organization. IT maintains a license inventory for all commercially licensed software and conducts quarterly audits to ensure compliance with vendor agreements. Installing unlicensed or pirated software is a serious policy violation and may have legal consequences.\n\nSoftware license requests are reviewed against available license inventory before new purchases are initiated. License pooling allows unused licenses to be reassigned to new users when previous users no longer require them. Employees are encouraged to notify IT when they stop using licensed software to allow reassignment.\n\nLicense compliance reports are provided to the CFO and CTO quarterly. During an audit, employees may be required to provide evidence of authorized software use. Automated license discovery tools run monthly on all managed devices. Unauthorized software found during discovery scans is uninstalled and the user is contacted for remediation.",
     "Software license management policy covering compliance obligations, license audits, and unauthorized software removal.",
     "software license,compliance,it policy,audit"),
    ("IT Support", "Cybersecurity Awareness Training Guide",
     "The annual cybersecurity awareness training program educates all employees on recognizing and responding to common cyber threats. Training covers phishing, social engineering, password hygiene, data handling, and safe browsing practices. Completion of the annual training is mandatory and is tracked in the Learning Management System.\n\nPhishing simulations are conducted quarterly using controlled test emails. Employees who click on simulation links receive immediate educational feedback and are enrolled in supplemental awareness training. Repeated failures in phishing simulations may be escalated for targeted security coaching with the IT Security team.\n\nBeyond mandatory training, the IT Security team publishes a monthly security newsletter with tips, threat intelligence updates, and case studies. Security Champions are designated in each department to promote good security practices and serve as the first point of contact for security questions. Employees can earn recognition through the Security Awareness Achievement program.",
     "Overview of the mandatory annual cybersecurity awareness program including phishing simulations and supplemental training resources.",
     "cybersecurity,training,awareness,phishing"),

    # Infrastructure (20)
    ("Infrastructure", "Monthly Server Maintenance Schedule",
     "Scheduled server maintenance is conducted on the second Sunday of each month between 2 AM and 6 AM to minimize business impact. All critical systems including the ERP, email, and customer portal are gracefully shut down 30 minutes before the maintenance window begins. Users are notified via email and the IT status page 48 hours in advance.\n\nDuring the maintenance window, the infrastructure team applies OS patches, firmware updates, and hardware health checks. Disk space, memory utilization, and CPU baselines are verified post-maintenance. Any changes made during the window are documented in the Change Management system with before-and-after configuration snapshots.\n\nEmergency maintenance outside of the scheduled window requires Change Advisory Board (CAB) approval for non-critical changes and CISO approval for security-critical patches. Emergency maintenance is classified as P1 and must be communicated to all stakeholders immediately. Post-emergency maintenance, a root cause analysis is completed within 48 hours and reviewed in the next scheduled CAB meeting.",
     "Monthly server maintenance schedule covering maintenance windows, notification procedures, and emergency maintenance escalation.",
     "server,maintenance,infrastructure,schedule"),
    ("Infrastructure", "Database Backup and Recovery Guide",
     "Production databases are backed up using a 3-2-1 backup strategy: 3 copies of data, on 2 different storage media, with 1 copy off-site. Full backups run every Sunday at 12 AM, incremental backups run daily at 11 PM, and transaction log backups run every 15 minutes for critical databases.\n\nBackup integrity is verified weekly through automated restore testing to a non-production environment. Any backup verification failure triggers an immediate P1 alert to the database team. Retention periods are: transaction logs 7 days, daily incremental 30 days, weekly full 90 days, monthly archive 1 year, and annual archive 7 years.\n\nFor a recovery event, the DBA team follows the approved Recovery Runbook. Recovery Time Objective (RTO) is 4 hours for tier-1 databases and 8 hours for tier-2. Recovery Point Objective (RPO) is 15 minutes for tier-1 and 1 hour for tier-2. All recovery exercises are tested during the annual Disaster Recovery drill.",
     "Database backup strategy covering backup schedules, retention policies, integrity testing, and recovery time objectives.",
     "database,backup,recovery,infrastructure"),
    ("Infrastructure", "Network Architecture Documentation",
     "The corporate network is segmented into distinct security zones to limit lateral movement in the event of a breach. The zones are: DMZ (internet-facing services), Corporate (employee workstations and printers), Server (application and database servers), Management (network devices and monitoring), and OT (operational technology where applicable).\n\nCore switching infrastructure uses a collapsed 3-tier architecture with redundant core, distribution, and access layer switches. Inter-zone traffic is controlled by next-generation firewalls with application-layer inspection. All zone transitions are logged to the SIEM for security monitoring. BGP is used for external routing and OSPF for internal routing.\n\nNetwork diagrams are maintained in the Confluence documentation space and updated within 5 business days of any topology change. Logical diagrams, physical diagrams, and IP address documentation are all version-controlled. Access to network diagrams is restricted to IT Infrastructure, Security, and approved architects due to the sensitivity of the information.",
     "Documentation of the corporate network architecture including security zones, routing protocols, and diagram maintenance procedures.",
     "network,architecture,documentation,infrastructure"),
    ("Infrastructure", "IT Disaster Recovery Plan",
     "The IT Disaster Recovery Plan defines the procedures for recovering critical IT systems and services following a major disruption. The plan covers scenarios including datacenter outages, ransomware attacks, natural disasters, and critical vendor failures. The plan is reviewed and updated annually and tested through a full simulation every 18 months.\n\nCritical systems are tiered by business impact: Tier 1 (Email, ERP, Core Network) must be recovered within 4 hours; Tier 2 (HR systems, File Shares) within 8 hours; Tier 3 (Reporting, Analytics) within 24 hours. Recovery is coordinated from a designated Crisis Command Center either on-site or virtually via the emergency bridge line.\n\nEach system has a designated recovery owner responsible for executing the system-specific runbook. All runbooks are stored in a hardened off-site documentation repository accessible even when primary systems are down. Recovery progress is tracked against a pre-defined milestone checklist and status is communicated to the Crisis Management Team every 30 minutes.",
     "IT Disaster Recovery Plan covering system tiers, recovery objectives, crisis command structure, and testing requirements.",
     "disaster recovery,drp,infrastructure,business continuity"),
    ("Infrastructure", "Load Balancer Configuration Guide",
     "Application load balancers distribute incoming traffic across multiple backend server instances to ensure high availability and horizontal scalability. The primary load balancer is configured in active-passive mode with automatic failover to the standby node if the primary becomes unresponsive for more than 30 seconds.\n\nHealth checks are configured on each backend pool with an interval of 10 seconds and a threshold of 3 consecutive failures before a node is removed from the pool. HTTP health check endpoints must return a 200 status within 2 seconds to be considered healthy. Nodes returning errors or taking longer than the threshold are gracefully drained before removal.\n\nSSL termination is handled at the load balancer layer. TLS 1.2 is the minimum required version; TLS 1.0 and 1.1 are disabled. Certificate renewals are automated through the PKI infrastructure and must be completed at least 14 days before expiry. Configuration changes to the load balancer require CAB approval and a maintenance window.",
     "Load balancer configuration guide covering failover settings, health checks, SSL termination, and change management requirements.",
     "load balancer,configuration,infrastructure,high availability"),
    ("Infrastructure", "SSL Certificate Renewal Procedure",
     "SSL/TLS certificates secure encrypted communications between clients and servers. All externally and internally trusted certificates are managed through the corporate PKI or a designated CA vendor. An automated monitoring tool tracks certificate expiry and generates alerts at 60, 30, and 14 days before expiration.\n\nFor renewal of certificates issued by the internal CA, the certificate owner submits a renewal request through the PKI portal with the certificate's Common Name, SAN entries, and key length (minimum 2048-bit RSA or 256-bit ECC). The renewed certificate is automatically installed if the system supports ACME protocol; otherwise, manual installation is required.\n\nPublic certificates from third-party CAs require domain validation or organization validation depending on the certificate type. The renewal process must be started no later than 30 days before expiry to allow time for validation and deployment. Any certificate allowed to expire without renewal will cause service disruptions and be treated as a P1 security incident.",
     "Procedure for monitoring, renewing, and deploying SSL/TLS certificates including expiry alerts and CA requirements.",
     "ssl,certificate,renewal,security"),
    ("Infrastructure", "Firewall Rules and Policy Documentation",
     "Firewall rules define the permitted and denied traffic flows between network zones. All firewall changes must be submitted as a Change Request with source/destination IP or subnet, port/protocol, direction, and business justification. Changes are reviewed by the Network Security team and approved through the CAB process.\n\nFirewall rule reviews are conducted every 6 months to identify and remove stale, overly permissive, or redundant rules. Rules that have had no traffic in 90 days are flagged for removal review. All rules must have an owner, expiry date for temporary rules, and a documented business justification. Rules created without proper documentation are subject to removal.\n\nEmergency firewall rules to address active security incidents can be applied by the on-call Network Security engineer without prior CAB approval. A retroactive change request must be submitted within 24 hours. All firewall rule changes are logged to the SIEM and retained for 1 year. Firewall configurations are backed up daily with 30-day retention.",
     "Policy and procedures for managing firewall rules including the change request process, rule reviews, and emergency exception handling.",
     "firewall,policy,network security,change management"),
    ("Infrastructure", "Cloud Infrastructure Overview",
     "The organization's cloud footprint spans AWS (primary) and Azure (secondary for Microsoft workloads). AWS is used for production application hosting, data analytics, and DevOps tooling. Azure is used for Microsoft 365, Azure Active Directory, and legacy workload migration.\n\nCloud resources are provisioned exclusively through Infrastructure-as-Code using Terraform and CloudFormation. Manual provisioning through cloud consoles is prohibited outside of approved sandbox accounts. All infrastructure changes go through the standard CI/CD pipeline with automated security scanning and approval gates.\n\nCloud cost governance is enforced through mandatory resource tagging (Owner, Environment, Department, Project) and budget alerts at 80% and 100% of monthly allocations. Untagged resources are automatically shutdown after 72 hours as a cost control measure. A Cloud Center of Excellence meets monthly to review usage, optimize costs, and establish architectural standards.",
     "Overview of the organization's AWS and Azure cloud footprint with governance, IaC requirements, and cost management practices.",
     "cloud,aws,azure,infrastructure"),
    ("Infrastructure", "System Monitoring and Alerting Setup",
     "The infrastructure monitoring stack uses Prometheus for metrics collection, Grafana for visualization, and PagerDuty for alert routing. All production systems must be onboarded to monitoring before go-live, with a minimum set of required metrics: CPU, memory, disk, and network utilization plus application-specific health checks.\n\nAlert thresholds are reviewed quarterly and tuned to minimize alert fatigue while ensuring genuine issues are caught. P1 alerts page the on-call engineer immediately via PagerDuty; P2 alerts send email and Slack notifications. Alert escalation paths are defined in the on-call runbook. All alerts must have an associated runbook linked in the alert description.\n\nDashboards are organized by service team and are shared with stakeholders through read-only Grafana links. SLA dashboards are visible to the Operations Management team and are updated every 5 minutes. Monitoring configuration is managed as code and versioned in the infrastructure Git repository.",
     "Setup and standards for the monitoring and alerting stack including metric requirements, alert thresholds, and on-call escalation.",
     "monitoring,alerting,infrastructure,operations"),
    ("Infrastructure", "Annual Capacity Planning Process",
     "Capacity planning is conducted annually during Q3 to inform the following year's infrastructure budget and procurement plan. The process covers compute, storage, network bandwidth, and licensing capacity across all production and non-production environments.\n\nEach service team provides a 12-month growth forecast based on business projections, user growth estimates, and planned feature releases. Infrastructure architects analyze current utilization trends and model capacity requirements against headroom targets. Production systems should maintain at least 30% headroom to absorb unplanned spikes.\n\nCapacity recommendations are consolidated into the IT Infrastructure Roadmap, which is presented to the CTO and CFO in November for budget approval. Approved procurement is initiated in January with delivery and installation completed by March. Interim capacity gaps identified outside the annual cycle are addressed through cloud bursting or emergency procurement with executive approval.",
     "Annual capacity planning process covering service team forecasting, utilization analysis, and infrastructure roadmap development.",
     "capacity planning,infrastructure,procurement,annual process"),
    ("Infrastructure", "Enterprise Storage Management Policy",
     "Enterprise storage resources are managed centrally by the Infrastructure team to ensure data integrity, availability, and cost efficiency. Production workloads use SAN (Storage Area Network) for block storage and NAS (Network-Attached Storage) for file-based workloads. All storage is replicated synchronously to the secondary datacenter.\n\nStorage provisioning requests must be submitted through the IT portal with the workload type, performance tier (standard, premium, ultra), estimated data size, and retention requirements. Storage quotas are enforced at the volume level; requests to increase quotas require manager approval. Storage utilization reports are reviewed monthly.\n\nDeprecated or unused storage volumes are identified during semi-annual storage audits. Volumes with no I/O activity for 90 days are flagged for decommission review. Secure data deletion using DOD 5220.22-M standard is applied to all storage volumes before decommission. Storage capacity forecasts are included in the annual capacity planning cycle.",
     "Enterprise storage management policy covering provisioning, quota management, auditing, and secure decommission procedures.",
     "storage,san,nas,infrastructure"),
    ("Infrastructure", "API Gateway Configuration Guide",
     "The organization's API Gateway serves as the single entry point for all external and internal API traffic. Kong is the primary API gateway platform, deployed in a highly available 3-node cluster across two datacenters. All API consumer applications must register through the Developer Portal before accessing any protected API.\n\nAuthentication for API consumers is enforced at the gateway level using OAuth 2.0 with JWT bearer tokens. API keys are supported for legacy integrations but are being deprecated in favor of OAuth. Rate limiting is applied at the consumer and route level; default limits are 1,000 requests per minute per consumer. Custom rate limit exceptions require the API owner's approval.\n\nAPI route configuration is managed through the Kong admin API and Deck (declarative configuration). Manual changes through the Kong Admin GUI are not permitted in production environments. All configuration changes must be versioned in Git and deployed through the CI/CD pipeline. Gateway performance metrics are monitored in Grafana with alerts for elevated error rates and latency.",
     "API Gateway configuration guide covering Kong setup, authentication standards, rate limiting, and deployment automation.",
     "api gateway,kong,configuration,infrastructure"),
    ("Infrastructure", "Docker Container Deployment Guide",
     "Containerized applications are deployed using Docker images built through the CI/CD pipeline. All images must be built from approved base images maintained in the internal container registry. Using unvetted public images from Docker Hub is prohibited in production without prior security review and approval.\n\nContainers are orchestrated using Kubernetes (EKS on AWS). All deployments must include resource requests and limits, liveness and readiness probes, and a pod disruption budget for availability. Secrets are managed through HashiCorp Vault and injected at runtime; never store secrets in environment variables or Docker images.\n\nContainer images are scanned for vulnerabilities by Trivy as part of the build pipeline. Images with Critical or High severity vulnerabilities are blocked from deployment to production. Container runtime security is monitored by Falco, which alerts on unexpected system calls or privilege escalations. Deployment runbooks for each containerized service are maintained in the team's documentation space.",
     "Guide for deploying Docker containers with Kubernetes including base image requirements, secrets management, and security scanning.",
     "docker,kubernetes,containers,deployment"),
    ("Infrastructure", "CI CD Pipeline Documentation",
     "The CI/CD pipeline automates code building, testing, security scanning, and deployment to ensure consistent and reliable software delivery. GitHub Actions is the primary CI platform with deployments orchestrated through ArgoCD for Kubernetes workloads and AWS CodeDeploy for traditional workloads.\n\nAll code commits trigger automated unit tests, integration tests, and static code analysis. Pull requests require at minimum 2 reviewer approvals and a passing pipeline before merge to the main branch. Security gates include SAST (Semgrep), SCA (Snyk), container scanning (Trivy), and IaC scanning (Checkov). Failed security gates block deployment automatically.\n\nProduction deployments require a manual approval gate from the release manager role after staging validation. Deployments use rolling updates or blue-green strategies to minimize downtime. Automated rollback is triggered if error rates exceed 5% within 10 minutes of deployment. Pipeline execution metrics and deployment frequency are tracked on the Engineering Excellence dashboard.",
     "CI/CD pipeline documentation covering build stages, security gates, deployment strategies, and automated rollback procedures.",
     "cicd,pipeline,devops,deployment"),
    ("Infrastructure", "Centralized Log Management Policy",
     "All production systems must ship logs to the centralized log management platform (Elastic Stack). Log sources include application logs, system logs, network device logs, security tool logs, and audit logs. Centralized logging enables security monitoring, compliance reporting, and operational troubleshooting from a single platform.\n\nLogs must be forwarded in real-time with a maximum acceptable lag of 30 seconds. Log format standardization uses the Elastic Common Schema (ECS) to ensure consistent parsing and correlation across log sources. Each log entry must include at minimum: timestamp, source system, log level, and a structured message.\n\nLog retention periods are: security logs 1 year, application logs 90 days, infrastructure logs 60 days, and debug logs 14 days. Access to log data is restricted by data classification; security logs require IT Security team membership. Tampering with or deleting logs is a serious security violation. WORM (Write Once Read Many) storage is used for audit-critical log categories.",
     "Centralized log management policy covering log sources, shipping requirements, retention periods, and access controls.",
     "logging,elk,siem,infrastructure"),
    ("Infrastructure", "Security Patch Management Schedule",
     "Security patches are categorized by CVSS severity and patched on a defined schedule: Critical (CVSS 9.0+): within 24 hours; High (7.0-8.9): within 7 days; Medium (4.0-6.9): within 30 days; Low (0.1-3.9): within 90 days. Patches for actively exploited vulnerabilities are treated as Critical regardless of CVSS score.\n\nPatch deployment follows a ring model: Development (immediately), QA (24 hours after dev), Staging (48 hours after QA), Production (72 hours after staging with CAB approval). Emergency patches may bypass the ring model with CISO and CTO approval. Patch testing in non-production is mandatory before production deployment.\n\nPatch compliance is measured weekly and reported to the CISO. Any production system missing a Critical or High patch beyond its deadline triggers an automatic P1 incident. Systems that cannot be patched within the defined window due to compatibility issues must have a documented compensating control approved by the CISO.",
     "Security patch management schedule covering severity categories, deployment ring model, and compliance reporting.",
     "patch management,security,schedule,infrastructure"),
    ("Infrastructure", "Infrastructure Cost Optimization Guide",
     "Infrastructure cost optimization is a continuous discipline supported by monthly FinOps reviews. Key optimization levers include right-sizing over-provisioned compute, utilizing reserved instances for predictable workloads, identifying and eliminating idle resources, and shifting suitable workloads to Spot instances.\n\nTagging compliance is foundational to cost attribution. Resources without mandatory tags (Owner, Environment, Department) are flagged weekly and owners are notified. Repeated non-compliance results in automatic resource shutdown. Cost anomaly alerts are configured to notify owners when daily spend exceeds 20% of the 7-day average.\n\nQuarterly optimization reviews produce a prioritized action plan with estimated savings. The top 5 optimization actions from each review must be implemented within 60 days. Cost optimization goals are tracked as engineering KPIs and reported to senior leadership quarterly. Savings achieved through optimization initiatives are credited to the department's IT budget.",
     "Cost optimization guide for cloud infrastructure covering right-sizing, reserved instances, tagging compliance, and FinOps reviews.",
     "cost optimization,cloud,finops,infrastructure"),
    ("Infrastructure", "DNS Zone Management Guide",
     "DNS zones are managed centrally through the corporate DNS management platform (Infoblox). External DNS is hosted on cloud DNS services (Route 53 for AWS, Azure DNS for Azure workloads). All DNS record changes must be submitted through the IT portal as a change request; direct modifications to DNS servers are not permitted.\n\nDNS record types in use include: A/AAAA for host records, CNAME for aliases, MX for mail routing, TXT for domain verification and SPF/DKIM/DMARC, and SRV for service discovery. TTL values are standardized: 300 seconds for frequently changing records and 3600 seconds for stable records. Low TTLs during planned changes are coordinated with the Network team.\n\nDNS change requests are approved by the network team lead and take effect within 1 hour of approval. Emergency DNS changes (e.g., incident response) can be expedited with on-call network engineer authorization. All DNS changes are logged and reviewed during post-incident analysis when DNS changes are implicated in service disruptions.",
     "DNS zone management guide covering record types, TTL standards, change request process, and emergency DNS procedures.",
     "dns,networking,infrastructure,configuration"),
    ("Infrastructure", "IP Address Management Policy",
     "IP Address Management (IPAM) is centralized using the Infoblox IPAM module to maintain an authoritative record of all IP allocations across the corporate network. All IP address assignments must be documented in IPAM, whether statically assigned or dynamically allocated through DHCP.\n\nIPv4 address space is allocated in blocks from the 10.0.0.0/8 RFC 1918 range following the documented subnet allocation plan. New subnet requests must be submitted through the IT portal with the number of hosts required, network zone, location, and owner. Subnets are sized to allow for 50% future growth minimum. IPv6 is supported in select network segments with dual-stack configuration.\n\nIPAM accuracy is verified through quarterly reconciliation scans that compare actual network traffic against documented allocations. Undocumented IP addresses found during reconciliation are investigated and either documented or quarantined. IPAM data is exported to the CMDB weekly to maintain configuration management accuracy.",
     "IP address management policy covering IPAM tool usage, subnet allocation standards, and quarterly reconciliation procedures.",
     "ipam,ip address,networking,infrastructure"),
    ("Infrastructure", "Quarterly System Audit Procedure",
     "Quarterly system audits verify that infrastructure components are compliant with security policies, configuration standards, and capacity thresholds. Audits cover all production systems in scope including servers, network devices, storage, and security appliances. Audit results feed into the Risk Register and Compliance Dashboard.\n\nThe audit process uses automated tools (Qualys for vulnerability assessment, Nessus for configuration compliance, and custom scripts for capacity checks) supplemented by manual review for complex configurations. Audit scope and sampling methodology are reviewed annually with the Internal Audit team to ensure alignment with risk priorities.\n\nAudit findings are classified as Critical, Major, or Minor. Critical findings require remediation within 7 days; Major within 30 days; Minor within 90 days. Findings that cannot be remediated within the target timeline require a formal risk acceptance signed by the CISO. Quarterly audit reports are shared with the IT Leadership team and relevant findings are included in the Board-level risk report.",
     "Quarterly system audit procedure covering scope, automated tools, finding classification, and remediation timelines.",
     "audit,compliance,infrastructure,security"),

    # Training Materials (20)
    ("Training Materials", "New Employee First Week Orientation",
     "The first week orientation program is designed to immerse new employees in the organization's culture, values, and core ways of working. Day one begins with a welcome breakfast hosted by HR, followed by a tour of the office facilities and introduction to the immediate team. System access and equipment should be fully set up before the new hire arrives.\n\nDays two and three are structured with department-specific onboarding sessions, including meetings with key stakeholders and an overview of the team's objectives, current projects, and workflow tools. New employees are assigned a 30-day buddy who is available for informal questions and cultural guidance throughout the first month.\n\nDays four and five include compliance and mandatory training modules covering data protection, workplace safety, information security awareness, and the Code of Conduct. New employees complete self-paced modules in the Learning Management System and attend a live Q&A session with an HR representative. A first-week check-in with the manager is scheduled for end of day five.",
     "First week orientation program covering office introduction, team onboarding, system setup, and mandatory compliance training.",
     "onboarding,orientation,new employee,training"),
    ("Training Materials", "Leadership Development Program Overview",
     "The Leadership Development Program (LDP) is a 12-month blended learning journey designed for high-potential individual contributors identified through the talent review process. The program develops strategic thinking, people leadership, business acumen, and executive presence through workshops, coaching, and stretch assignments.\n\nThe program is structured in four quarterly phases: Foundation (leadership styles and self-awareness), Amplification (influencing and stakeholder management), Acceleration (business strategy and change leadership), and Integration (capstone project and peer teaching). Each phase includes a 2-day in-person workshop, monthly group coaching calls, and curated self-paced learning content.\n\nParticipants are paired with a senior leader mentor for the duration of the program. A capstone project addressing a real business challenge is presented to the executive leadership team at program completion. Graduates are tracked through the succession planning process and prioritized for stretch assignments and leadership vacancies.",
     "Overview of the 12-month Leadership Development Program for high-potential employees covering curriculum, coaching, and capstone project.",
     "leadership,development,training,program"),
    ("Training Materials", "Technical Skills Development Path",
     "The Technical Skills Development Path provides a structured curriculum for engineering and technical roles to build proficiency across core technology disciplines. Paths are defined for six role families: Software Engineering, Data Engineering, Infrastructure, Security, QA, and Product. Each path includes foundational, intermediate, and advanced levels.\n\nEach skill level has a recommended set of courses, certifications, and practical exercises. Progress through skill levels is tracked in the Learning Management System and reviewed during the performance cycle. Employees are expected to complete the foundational level within their first 6 months and the intermediate level within 18 months.\n\nTechnical skills assessments are conducted annually to validate proficiency and identify gaps. Assessment results inform individual development plans and team capability planning. Subject matter experts from each domain facilitate monthly learning clinics on emerging technologies and advanced topics to supplement the structured curriculum.",
     "Structured technical skills development curriculum for engineering roles covering foundational, intermediate, and advanced skill levels.",
     "technical skills,development,engineering,training"),
    ("Training Materials", "Customer Service Excellence Training",
     "Customer Service Excellence Training is mandatory for all client-facing roles and is recommended for any employee who interacts with internal stakeholders. The program covers the organization's service philosophy, communication standards, complaint handling, and escalation procedures.\n\nCore modules include: Understanding Customer Needs (active listening, empathy mapping, and needs assessment), Effective Communication (verbal, written, and digital communication best practices), Handling Difficult Situations (de-escalation, conflict resolution, and setting expectations), and Service Recovery (acknowledging failures and exceeding expectations in recovery).\n\nThe program combines self-paced e-learning modules with a 1-day in-person workshop featuring role-playing exercises and peer feedback. Participants are evaluated through a practical assessment scored by the facilitator and a customer satisfaction simulation. Annual refreshers are required to maintain certification. Post-training follow-up coaching is available for employees who score below the proficiency threshold.",
     "Customer service excellence training covering communication standards, complaint handling, and service recovery techniques.",
     "customer service,training,communication,soft skills"),
    ("Training Materials", "Product Knowledge Base Guide",
     "The Product Knowledge Base is the definitive internal reference for all product lines, features, pricing, and competitive positioning. All customer-facing employees are required to complete product knowledge training within their first 60 days and pass the product knowledge assessment with a minimum score of 80%.\n\nThe knowledge base is organized by product family and includes feature descriptions, use case scenarios, technical specifications, pricing tiers, and frequently asked questions. Product release notes are published within 5 business days of each release, and knowledge base articles are updated accordingly. A notification is sent to all subscribed users when material changes are published.\n\nProduct champions in each business unit are responsible for ensuring their team's product knowledge is current. Quarterly product knowledge reviews are conducted to identify gaps and update materials. A certification program is available for employees who want to demonstrate advanced product expertise and is a requirement for senior client-facing roles.",
     "Guide to the internal product knowledge base including content organization, update processes, and certification requirements.",
     "product knowledge,training,certification,sales enablement"),
    ("Training Materials", "Annual Compliance Training Guide",
     "Annual compliance training is mandatory for all employees and must be completed by December 31st each year. Failure to complete by the deadline results in system access restrictions until completion. The training covers regulatory requirements, company policies, and ethical standards relevant to each employee's role and location.\n\nCore modules required for all employees include: Data Privacy (GDPR, CCPA), Anti-Bribery and Corruption, Anti-Money Laundering, Information Security Awareness, and the Code of Conduct refresher. Additional role-specific modules are assigned based on job function, covering areas such as financial regulations, health and safety, and export controls.\n\nTraining is delivered through the Learning Management System with a mix of interactive modules, video content, and scenario-based assessments. Each module must be completed with a minimum score of 75% to be marked complete. Completion rates are reported to the Compliance Committee monthly and to the Board annually. Managers are responsible for their team's completion rates.",
     "Annual mandatory compliance training guide covering required modules, completion deadlines, and reporting requirements.",
     "compliance,training,mandatory,annual"),
    ("Training Materials", "Workplace Safety Training Manual",
     "Workplace safety training is mandatory for all employees and contractors before they can access company facilities. The training covers hazard identification, emergency procedures, equipment safety, ergonomics, and first aid response. Site-specific safety orientations are provided for employees working in manufacturing, lab, or warehouse environments.\n\nThe Safety Training Manual is organized into four sections: Emergency Response (fire, medical, evacuation), Hazard Communication (chemical handling, safety data sheets), Personal Protective Equipment (selection, use, and maintenance), and Ergonomics (workstation setup, safe lifting, and repetitive motion prevention).\n\nSafety training is refreshed annually with a focus on near-miss incidents, audit findings, and updated regulatory requirements. Employees who witness or experience a safety incident are required to complete an incident-specific supplemental module within 5 business days. Safety training completion is tracked in the HR system and is an input to the facility's safety certification status.",
     "Workplace safety training manual covering emergency response, hazard communication, PPE, and ergonomics for all facility users.",
     "safety,training,manual,compliance"),
    ("Training Materials", "Enterprise Software Training Guide",
     "The Enterprise Software Training Guide provides structured learning paths for the core business applications used across the organization. Covered systems include the ERP (SAP S/4HANA), CRM (Salesforce), ITSM (ServiceNow), and collaboration tools (Microsoft 365). Training paths are role-based to ensure relevance.\n\nEach system training path includes a beginner module (system navigation, key concepts, and basic transactions), an intermediate module (advanced features, reporting, and integrations), and a role-specific module tailored to the employee's job function. Training is delivered through a combination of self-paced e-learning, virtual instructor-led sessions, and practice environments.\n\nThe ERP and CRM systems require mandatory certification before production access is granted. Certifications are valid for 24 months and must be renewed through the refresher module and assessment. The IT training team maintains a library of job aids, quick reference cards, and tutorial videos accessible through the Learning Management System at any time.",
     "Role-based training guide for core enterprise software systems including ERP, CRM, ITSM, and Microsoft 365.",
     "enterprise software,training,erp,crm"),
    ("Training Materials", "Business Communication Skills Workshop",
     "The Business Communication Skills Workshop is a 2-day intensive program designed to improve written, verbal, and presentation communication across all employee levels. Effective communication is a core competency for career advancement and is incorporated into the annual performance review framework.\n\nDay one focuses on written communication: structuring emails and documents, adapting tone for different audiences, executive summary writing, and business report formatting. Participants practice with real-world scenarios and receive peer and facilitator feedback. Common pitfalls such as excessive jargon, ambiguous language, and imprecise requests are addressed through editing exercises.\n\nDay two covers verbal and presentation skills: structuring a presentation narrative, managing nerves, handling Q&A with confidence, and facilitating productive meetings. Each participant delivers a 10-minute presentation and receives structured feedback from peers and the facilitator. Post-workshop, participants commit to one communication goal documented in their development plan.",
     "2-day intensive workshop covering written, verbal, and presentation communication skills for business professionals.",
     "communication,workshop,training,soft skills"),
    ("Training Materials", "Project Management Fundamentals",
     "Project Management Fundamentals is an introductory course covering the key principles, processes, and tools used to plan and deliver projects successfully. The course is recommended for all employees who lead initiatives, coordinate cross-functional work, or aspire to project management roles.\n\nThe curriculum covers the project lifecycle (Initiation, Planning, Execution, Monitoring, and Closing), scope and change management, stakeholder communication planning, risk identification and mitigation, and resource planning. Participants learn to create a project charter, work breakdown structure, risk register, and communication plan through hands-on exercises.\n\nThe course concludes with a capstone exercise where groups plan and present a simulated project. A practical toolkit including templates for all key project management documents is provided to all participants. The course serves as a foundation for the PMI PMP certification path, which is available with manager approval for employees in project-intensive roles.",
     "Introductory project management course covering lifecycle, scope management, risk, and communication planning with practical templates.",
     "project management,pmp,training,fundamentals"),
    ("Training Materials", "Agile and Scrum Methodology Training",
     "The Agile and Scrum Methodology Training equips development and product teams with the knowledge to work in iterative, cross-functional delivery cycles. The training covers the Agile Manifesto and principles, Scrum framework (roles, events, and artifacts), and practical guidance for transitioning from waterfall or hybrid approaches.\n\nCore modules include: Introduction to Agile (values, principles, and common misconceptions), Scrum Deep Dive (Sprint planning, Daily Standup, Sprint Review, and Retrospective), Backlog Management (writing user stories, acceptance criteria, and prioritization techniques), and Scaling Agile (an introduction to SAFe and LeSS for program-level coordination).\n\nThe course is delivered over 2 days with a mix of theory, case studies, and Agile simulation exercises (including a Scrum simulation using physical cards and boards). Participants who complete the training and a follow-on assessment are eligible to sit the Certified ScrumMaster (CSM) examination, with company sponsorship available for development roles.",
     "Agile and Scrum training covering the Scrum framework, backlog management, and foundations for CSM certification.",
     "agile,scrum,training,methodology"),
    ("Training Materials", "Data Analysis for Beginners",
     "Data Analysis for Beginners is an entry-level course designed for non-technical employees who want to work more effectively with data in their roles. No prior programming or statistics knowledge is required. The course focuses on practical skills using Microsoft Excel and Power BI as the primary tools.\n\nThe curriculum covers: Understanding Data Types and Structures, Data Cleaning and Preparation in Excel, Summarizing Data with Pivot Tables and Charts, Introduction to Power BI Desktop (data import, data model, and creating interactive reports), and Interpreting Data Visualizations to drive business decisions.\n\nEach module includes hands-on exercises using sample business datasets relevant to common use cases in HR, Finance, and Operations. Participants complete a final capstone project where they analyze a provided dataset and present three business insights using Power BI. The course is a prerequisite for the intermediate Data Analytics certification track.",
     "Entry-level data analysis course for non-technical employees using Excel and Power BI with practical business datasets.",
     "data analysis,excel,power bi,training"),
    ("Training Materials", "Effective Presentation Skills Guide",
     "Delivering a compelling presentation requires careful preparation, confident delivery, and audience engagement. This guide covers the complete presentation development process from defining your objective to managing post-presentation follow-ups.\n\nStructuring your presentation follows the INTRO method: Issue (what problem or opportunity are we addressing), Need (why this matters to the audience), Timeline (what is the current state vs. desired future state), Resolution (your recommended course of action), and Outcome (the expected results and next steps). Visual design principles covered include slide structure, font hierarchy, color usage, and data visualization best practices.\n\nDelivery techniques include managing the pace of speech, using strategic pauses, making eye contact across the room, and using body language purposefully. Handling challenging Q&A sessions and redirecting off-topic questions are practiced through role-play exercises. A self-assessment checklist is provided for post-presentation reflection.",
     "Comprehensive guide to developing and delivering presentations using the INTRO method with visual design and delivery technique tips.",
     "presentation,communication,training,soft skills"),
    ("Training Materials", "Time and Priority Management Workshop",
     "The Time and Priority Management Workshop addresses one of the most common challenges for knowledge workers: managing competing demands while maintaining focus on high-impact activities. The workshop is a half-day program delivered monthly and is recommended for all employees regardless of experience level.\n\nCore frameworks covered include: Eisenhower Matrix (urgent vs. important prioritization), Time Blocking (scheduling focused work periods to protect deep work time), Energy Management (aligning task complexity with natural energy rhythms), and the Weekly Review (a structured reflection and planning practice to maintain direction).\n\nParticipants leave the workshop with a personalized time audit, a set of commitments for behavioral changes to implement immediately, and a 30-day accountability partner. Follow-up digital content including a habit tracker and reference cards is shared through the Learning Management System. Post-workshop surveys show that 78% of participants report measurable improvement in focus and reduced stress within 30 days.",
     "Half-day workshop on time and priority management covering the Eisenhower Matrix, time blocking, and weekly review practices.",
     "time management,priority,productivity,workshop"),
    ("Training Materials", "Workplace Conflict Resolution Training",
     "Workplace Conflict Resolution Training equips employees and managers with skills to address and resolve interpersonal conflicts constructively before they escalate. Research shows that unaddressed conflict costs organizations an average of 2.8 hours of productivity per employee per week.\n\nThe training covers the conflict escalation model (Disagreement → Tension → Crisis → Dispute), active listening and perspective-taking techniques, interest-based negotiation (addressing underlying needs rather than stated positions), and structured conversation frameworks for delivering and receiving difficult feedback.\n\nManagers receive an additional module covering mediation facilitation, when to involve HR, and documentation of conflict resolution agreements. Role-play scenarios covering common workplace conflicts — competing priorities, communication breakdowns, and perceived unfairness — are used to practice the frameworks in a safe environment. Post-training 30-day coaching check-ins are available from the HR team.",
     "Training on conflict resolution techniques for employees and managers covering de-escalation, active listening, and structured conversations.",
     "conflict resolution,training,communication,hr"),
    ("Training Materials", "Mentorship Program Handbook",
     "The Corporate Mentorship Program pairs employees at different career stages to facilitate knowledge transfer, professional development, and cultural integration. The program runs two cohorts annually (January and July) with a 6-month commitment. Applications are open to all employees with manager endorsement.\n\nMentors and mentees are matched based on development goals, functional background, and stated preferences submitted in the application. The matching algorithm is supplemented by program coordinators to ensure compatibility. Both parties commit to meeting at least twice per month for structured conversations using the provided conversation guide.\n\nThe handbook includes: Program expectations and etiquette, Conversation guide and suggested topic areas for each phase of the mentorship, Goal-setting template, Mid-program check-in questions, and Closing reflection framework. Program administrators track engagement through quarterly check-in surveys. Program graduates are invited to become mentors in the following cohort.",
     "Handbook for participants in the corporate mentorship program covering expectations, conversation guides, and goal-setting tools.",
     "mentorship,career development,training,program"),
    ("Training Materials", "Cross Department Collaboration Training",
     "Cross-Department Collaboration Training addresses the organizational and interpersonal barriers that prevent teams from working effectively across functions. Siloed thinking, competition for resources, and misaligned incentives are the most common root causes of collaboration breakdowns.\n\nThe training introduces the concept of Organizational Network Analysis and helps participants map their actual collaboration patterns versus their formal reporting structure. Participants learn techniques for building trust across team boundaries, managing joint accountabilities without direct authority, and navigating conflicting departmental priorities through principled negotiation.\n\nA practical framework for cross-functional project governance — covering charter, RACI definition, decision-making protocols, and conflict escalation paths — is taught and applied to a current or near-term collaboration challenge from each participant. Post-training, a community of practice for cross-functional leaders meets monthly to share experiences and continue developing collaborative leadership skills.",
     "Training on cross-functional collaboration covering organizational networks, trust-building, and governance frameworks for joint projects.",
     "collaboration,cross-functional,training,leadership"),
    ("Training Materials", "Innovation and Design Thinking Workshop",
     "The Innovation and Design Thinking Workshop introduces a human-centered approach to problem-solving that combines empathy, creativity, and experimentation. The workshop is a 1-day immersive program using real business challenges submitted by participants ahead of the session.\n\nThe workshop follows the Stanford d.school Design Thinking process: Empathize (building deep user understanding through interviews and observation), Define (synthesizing insights into a clear problem statement), Ideate (generating a high volume of diverse solutions through structured brainstorming), Prototype (creating low-fidelity representations of promising ideas), and Test (rapid user feedback to iterate toward a viable solution).\n\nParticipant teams leave the workshop with a tested prototype concept and a 30-day action plan for piloting their best idea. Senior sponsors review prototypes at the end of the day and identify ideas with investment potential. The program is a feeder into the Corporate Innovation Fund, which grants up to $25,000 for internal innovation projects that demonstrate validated user value.",
     "1-day Design Thinking workshop using the Stanford d.school process for innovation, prototyping, and rapid user feedback.",
     "innovation,design thinking,workshop,creativity"),
    ("Training Materials", "Digital Workplace Literacy Training",
     "Digital Workplace Literacy Training ensures all employees can effectively use the digital tools and platforms that support modern work. As the digital toolset evolves, this training program is updated annually to reflect new platform introductions and capability upgrades.\n\nCore modules cover: Microsoft 365 productivity (Teams, SharePoint, OneNote, and Planner), Collaboration best practices (when to use email vs. chat vs. video, meeting etiquette, and asynchronous communication), Digital file management (naming conventions, folder structures, and version control in SharePoint), and Automation basics (an introduction to Power Automate for workflow automation without coding).\n\nThe training is self-paced with an estimated completion time of 4 hours. An optional advanced track covers Microsoft Power Apps, Power BI basics, and advanced Teams administration for power users. Assessments confirm practical competency; employees who demonstrate high proficiency in the assessment are awarded the Digital Champion badge and recognized in the company newsletter.",
     "Digital workplace literacy training covering Microsoft 365 tools, collaboration best practices, and automation basics for all employees.",
     "digital literacy,microsoft 365,training,tools"),
    ("Training Materials", "Diversity Equity and Inclusion Training",
     "Diversity, Equity, and Inclusion (DEI) Training is a mandatory annual program that builds awareness, skills, and commitment to creating an inclusive workplace where every employee can contribute fully. The training acknowledges that DEI is an ongoing journey, not a one-time event.\n\nCore modules include: Understanding Unconscious Bias (recognizing implicit associations and their impact on decisions), Allyship in Action (moving from awareness to active support for colleagues from underrepresented groups), Inclusive Leadership (creating psychological safety and equitable access to opportunities), and Microaggressions (identifying, interrupting, and addressing subtle forms of bias).\n\nThe training combines research-backed content with real-world scenarios drawn from employee experience surveys. Each module includes a personal reflection exercise and a commitment to one specific behavior change. An optional advanced track is available for managers and covers hiring for diversity, equitable performance management, and running inclusive team meetings. Completion is reported to the Board as part of the ESG scorecard.",
     "Mandatory annual DEI training covering unconscious bias, allyship, inclusive leadership, and microaggressions for all employees.",
     "diversity,equity,inclusion,training"),

    # Finance (20)
    ("Finance", "Employee Expense Reimbursement Policy",
     "Employees may be reimbursed for necessary and reasonable business expenses incurred while performing company-related duties. All expense claims must be submitted within 30 days of incurring the expense; late submissions beyond 90 days will not be processed. Expenses must be supported by original receipts for any amount over $25.\n\nEligible expenses include business travel (transport, accommodation, meals within per diem), client entertainment (pre-approved and within limits), office supplies for home offices, and professional development materials. Non-eligible expenses include alcohol beyond standard meal service, personal grooming, traffic fines, and entertainment without a documented business purpose.\n\nExpense reports are submitted through the Concur expense management system, reviewed by the employee's manager, and processed by Finance within 5 business days of approval. Reimbursements are paid through the regular payroll cycle. Suspected fraudulent expense claims are referred to HR and Internal Audit for investigation and may result in termination and legal action.",
     "Employee expense reimbursement policy covering eligible expenses, submission deadlines, required receipts, and payment timelines.",
     "expense,reimbursement,finance,policy"),
    ("Finance", "Annual Budget Planning Process",
     "The annual budget planning cycle begins in September and concludes with board approval in December for the following fiscal year. The process is coordinated by the Finance Business Partnering team with input from all department heads, operations leads, and the executive leadership team.\n\nDepartment heads receive budget templates and guidelines in September with high-level growth and cost targets set by Finance. Departmental budget submissions are due by October 15th, including headcount plans, capital expenditure requests, and program investment proposals with supporting ROI analysis. Finance consolidates submissions and conducts variance reviews with each department.\n\nThe consolidated budget is presented to the Executive Leadership Team in November for alignment on strategic priorities and trade-offs. Board approval is sought in December's board meeting. Approved budgets are loaded into the ERP system by January 5th. Budget holders receive monthly variance reports comparing actuals to budget with commentary required for variances exceeding 10%.",
     "Annual budget planning process covering submission timeline, department responsibilities, and board approval workflow.",
     "budget,planning,finance,annual process"),
    ("Finance", "Vendor Invoice Processing Guide",
     "Vendor invoices must be submitted to accounts@company.com or through the supplier portal within 5 business days of delivery. Invoices must include the purchase order number, vendor name and tax ID, itemized description of goods or services, amount, and payment terms. Invoices without a valid PO number are returned to the vendor for correction.\n\nThree-way matching is performed by the Accounts Payable team against the PO, goods receipt, and invoice before payment is approved. Discrepancies are communicated to the vendor and the internal requester within 2 business days. Disputed invoices are placed on hold until resolution; the AP team tracks and resolves all disputed invoices within 10 business days.\n\nStandard payment terms are net-30. Early payment discounts offered by vendors are evaluated against working capital considerations. Payments are processed in weekly payment runs on Thursdays. Urgent payment requests outside the normal cycle require CFO approval. All vendors must complete a due diligence review and be approved by Finance before invoices are processed.",
     "Vendor invoice processing guide covering submission requirements, three-way matching, dispute resolution, and payment timelines.",
     "vendor,invoice,accounts payable,finance"),
    ("Finance", "Company Procurement Policy",
     "All procurement activities must be conducted in accordance with this policy to ensure value for money, ethical sourcing, and compliance with regulatory requirements. Purchases below $5,000 can be approved by the budget holder. Purchases between $5,000 and $25,000 require manager approval. Purchases above $25,000 require a competitive tender process with a minimum of 3 quotes.\n\nPurchases exceeding $100,000 must be approved by the CFO and documented in a formal business case. The Procurement team facilitates the tender process and maintains a register of approved vendors. Employees must not split orders to circumvent approval thresholds; doing so is treated as a serious control violation.\n\nAll vendor agreements must be reviewed by Legal before signing. Contracts above $50,000 require the CEO's signature. The Procurement team maintains a preferred vendor list with negotiated terms; using preferred vendors is mandatory where they can meet the requirement. Vendor conflicts of interest must be disclosed in writing before any procurement engagement.",
     "Procurement policy covering approval thresholds, competitive tender requirements, vendor management, and conflict of interest rules.",
     "procurement,purchasing,vendor,policy"),
    ("Finance", "Monthly Financial Reporting Standards",
     "Monthly financial reports are prepared by the Finance team and distributed to budget holders by the 10th business day of the following month. Reports include the income statement, balance sheet, cash flow statement, and departmental variance analysis against budget and prior year.\n\nBudget holders must review their departmental variance reports and submit explanatory commentary for any line item with a variance exceeding 10% of budget or $10,000, whichever is less. Commentary must be submitted through the FP&A portal by the 15th business day. Recurring unexplained variances are escalated to the CFO.\n\nConsolidated financial reports for board and investor audiences are prepared using the management accounts as a base, with adjustments for one-time items, IFRS compliance adjustments, and foreign currency translation. The external audit team has read access to all financial reports and supporting documentation. Financial data must not be shared outside the organization without CFO approval.",
     "Monthly financial reporting standards covering report preparation timelines, variance commentary requirements, and data governance.",
     "financial reporting,finance,monthly,standards"),
    ("Finance", "Internal Audit Preparation Guide",
     "Internal audits are conducted by the Internal Audit function on a risk-based schedule. Departments are notified 4 weeks before an audit begins, and the audit fieldwork typically spans 2 to 3 weeks. This guide helps departments prepare efficiently and ensure a smooth audit process.\n\nPrepare the following documentation before the audit fieldwork begins: current process flowcharts, risk and control matrices, evidence of recent self-assessments, transaction samples as requested, and a list of open items from the previous audit cycle. Designate a single point of contact (audit liaison) from your department to coordinate with the audit team.\n\nDuring fieldwork, respond to auditor document requests within 24 hours. Interviews should be conducted with the nominated individuals only; redirecting auditors to alternate contacts without cause is not acceptable. Preliminary findings are shared with the department head at the end of fieldwork; formal draft reports are issued within 10 business days. Management responses to findings must be submitted within 15 business days of receiving the draft report.",
     "Preparation guide for internal audit fieldwork covering documentation requirements, liaison responsibilities, and response timelines.",
     "internal audit,compliance,finance,preparation"),
    ("Finance", "Corporate Tax Compliance Guide",
     "The Tax function manages the organization's compliance with all applicable tax obligations including corporate income tax, VAT/GST, payroll tax, and withholding tax. The tax calendar is maintained by the Tax Manager and highlights all filing and payment deadlines across all jurisdictions in which the organization operates.\n\nDepartments must provide the Tax team with requested data in a timely manner to support tax filings. Common data requests include intercompany transaction data, fixed asset schedules, payroll data, and capital expenditure registers. Failure to provide data on time may result in late filing penalties which will be charged back to the responsible department.\n\nTransfer pricing is managed in accordance with arm's-length principles and documented in the annual Transfer Pricing Policy. Any new intercompany arrangements must be reviewed and approved by Tax before implementation. R&D tax credits are claimed annually and require documentation of qualifying activities from the relevant technical teams. Tax risks are reported in the risk register and reviewed by the Audit Committee.",
     "Corporate tax compliance guide covering filing obligations, data requirements, transfer pricing, and R&D tax credit procedures.",
     "tax,compliance,finance,corporate"),
    ("Finance", "Payroll Processing Schedule and Policy",
     "Payroll is processed on a bi-weekly cycle with pay dates on the 15th and last business day of each month. The payroll cutoff for each cycle is 5 business days before the pay date. Any changes to salaries, deductions, or new hires must be submitted to HR by the cutoff deadline to be reflected in the current pay period.\n\nPayroll changes requiring Finance approval include: new hire salary offers above grade midpoint, salary increases exceeding 15%, and one-time bonus payments above $10,000. Changes that miss the cutoff deadline are processed in the following pay cycle. Emergency off-cycle payments are available for genuine errors in payroll processing; requests must be approved by the CFO.\n\nPayroll data is highly confidential and access is restricted to the Payroll team, HR Business Partners, and Finance leadership. Payroll records are retained for a minimum of 7 years in compliance with employment law requirements. Payroll reconciliations are performed monthly by the Finance team and reviewed by an independent reviewer to ensure accuracy and prevent fraud.",
     "Payroll processing schedule covering cutoff deadlines, approval requirements, off-cycle payments, and data confidentiality rules.",
     "payroll,finance,schedule,policy"),
    ("Finance", "Cost Center Management Guide",
     "Cost centers are the primary dimension for tracking and controlling departmental expenditure. Each cost center has a designated owner who is accountable for the budget and financial performance of that unit. Cost center owners receive monthly variance reports and are responsible for managing spend within approved budget limits.\n\nNew cost centers or changes to existing cost center structures must be requested through the Finance portal and are processed by the Management Accounting team. Cost center changes take effect at the start of the next fiscal month. Historical transactions are not reclassified retrospectively unless an error has occurred.\n\nAll purchase orders, expense reports, and journal entries must be assigned to a valid cost center and account code combination. Transactions posted to incorrect codes must be corrected through a journal transfer within the same accounting period; transfers across prior periods require Finance Director approval. Month-end cost center reports are locked 5 business days after the close of the reporting period.",
     "Guide to cost center management covering owner responsibilities, structural changes, and transaction posting requirements.",
     "cost center,finance,management accounting,policy"),
    ("Finance", "Vendor and Supplier Payment Process",
     "Approved vendor invoices are included in the weekly payment run processed every Thursday. The payment run covers invoices with a due date within the next 7 days and any overdue invoices requiring immediate settlement. Payment files are generated by the AP system and require dual authorization from two Finance team members before release.\n\nPayments are made by bank transfer to pre-registered vendor bank accounts. Changes to vendor banking details must be validated through a multi-step verification process including a call-back to the vendor's registered phone number using contact details from the original vendor master file, not from the change request itself. This control is critical to prevent payment fraud.\n\nInternational payments in foreign currencies are processed using the corporate treasury's pre-agreed exchange rates. Requests for same-day payment processing are subject to a $25 fee passed to the requesting department. The AP aging report is reviewed weekly by the Finance Manager to identify overdue invoices and manage supplier relationships.",
     "Vendor payment process covering weekly payment runs, bank detail change controls, and foreign currency payment procedures.",
     "vendor payment,accounts payable,finance,treasury"),
    ("Finance", "Capital Expenditure Approval Policy",
     "Capital expenditure (CapEx) refers to investments in assets with a useful life greater than one year and a cost above the capitalization threshold of $5,000. All CapEx must be included in the approved annual capital budget. Unbudgeted CapEx above $50,000 requires a formal business case with NPV, IRR, and payback period analysis.\n\nCapEx requests are approved based on the following authority matrix: up to $25,000 (Department Head); $25,000-$100,000 (CFO); $100,000-$500,000 (CEO); above $500,000 (Board approval required). Emergency CapEx required to prevent business disruption may be approved by the CFO regardless of amount, with Board ratification at the next meeting.\n\nAll CapEx projects are tracked in the CapEx register maintained by Finance. Project milestones, spend-to-date, and forecast-to-complete are reviewed monthly. Assets are placed in service and depreciation commences in the month they become operational. Disposal of capitalized assets requires Finance and Legal review to ensure proper accounting and contract termination.",
     "Capital expenditure approval policy covering capitalization threshold, authority matrix, and project tracking requirements.",
     "capex,capital expenditure,finance,approval"),
    ("Finance", "Internal Financial Controls Guide",
     "Internal financial controls are the policies, procedures, and systems that safeguard company assets, ensure financial reporting accuracy, and support compliance with laws and regulations. Control owners are designated for each key control activity and are responsible for maintaining their effectiveness.\n\nKey control categories include: Authorization controls (approval requirements for transactions), Segregation of duties (ensuring no single person controls all steps of a transaction), Reconciliation controls (monthly bank, AP, AR, and payroll reconciliations), IT general controls (access management, change management, and backup for financial systems), and Physical controls (secure storage of negotiable instruments and sensitive financial records).\n\nControl effectiveness is assessed quarterly through control self-assessments completed by control owners. Internal Audit independently tests a sample of key controls each quarter. Deficiencies are classified by severity and tracked to remediation. Material weaknesses identified in key financial controls are escalated immediately to the CFO and Audit Committee.",
     "Internal financial controls guide covering control categories, self-assessment procedures, and deficiency escalation protocols.",
     "internal controls,finance,compliance,audit"),
    ("Finance", "Petty Cash Management Procedure",
     "Petty cash funds are maintained by designated custodians in approved office locations for small, low-value business purchases that are impractical to process through the purchase order system. Petty cash funds are limited to a maximum float of $500 per location. Purchases from petty cash are limited to $100 per transaction.\n\nAll petty cash disbursements must be supported by an original receipt and a completed petty cash voucher showing the date, amount, payee, business purpose, and the signature of the recipient and the custodian. Petty cash is reconciled weekly by the custodian and verified monthly by a Finance team member independent of the custodian.\n\nWhen the petty cash fund drops below $200, the custodian submits a reimbursement request to Finance with all supporting vouchers and receipts. Reimbursements are processed within 2 business days. Petty cash funds are subject to unannounced spot audits by Internal Audit. Custodians who are found to have misappropriated petty cash are subject to disciplinary action and civil recovery.",
     "Petty cash management procedure covering fund limits, transaction requirements, reconciliation schedules, and custodian responsibilities.",
     "petty cash,finance,controls,procedure"),
    ("Finance", "Corporate Credit Card Usage Policy",
     "Corporate credit cards are issued to employees in roles that regularly incur business expenses. Eligibility requires manager approval and a clean expense policy compliance record. Cards are issued in the employee's name and are for business use only; personal charges are strictly prohibited and will be recovered through payroll deduction.\n\nCredit card transactions must be substantiated in the Concur expense system within 10 days of the transaction date. Transactions not substantiated within 30 days are escalated to the cardholder's manager. Itemized receipts are required for all transactions. Monthly credit card statements are reviewed by Finance to identify policy compliance issues and unusual patterns.\n\nCards are cancelled immediately upon resignation or termination, and the physical card must be returned to HR on the last day of employment. Credit limits are reviewed annually and adjusted based on spending patterns and business needs. Fraudulent or unauthorized transactions must be reported to the card provider and Finance within 24 hours of discovery.",
     "Corporate credit card policy covering eligibility, substantiation requirements, personal use prohibition, and card management.",
     "credit card,expense,finance,policy"),
    ("Finance", "Financial Year End Closing Process",
     "The financial year-end closing process ensures that all financial transactions for the fiscal year are accurately recorded and reported before the books are closed. The timeline is critical and all deadlines must be strictly observed to enable timely auditor access and board reporting.\n\nKey milestones include: Final transaction posting deadline (December 28), Accruals and prepayments deadline (January 3), Intercompany reconciliation completion (January 5), Draft trial balance review (January 8), Audit evidence package submission (January 12), and Preliminary results to CFO (January 15). The Finance team operates extended hours during the close period.\n\nYear-end accruals must be supported by documentation (contracts, invoices, or management estimates with methodology) and approved by the Finance Director. Prior year accruals are reviewed and released only with Finance Director approval. All journal entries during year-end close require two-person approval. A lessons-learned review is conducted in January to identify close process improvements for the following year.",
     "Financial year-end closing process covering transaction deadlines, accrual requirements, audit preparation, and key milestones.",
     "year end,closing,finance,audit"),
    ("Finance", "Revenue Recognition Policy",
     "Revenue is recognized in accordance with IFRS 15 (Revenue from Contracts with Customers) using the five-step model: identify the contract, identify performance obligations, determine transaction price, allocate the transaction price, and recognize revenue when performance obligations are satisfied.\n\nFor subscription contracts, revenue is recognized ratably over the subscription period. For professional services, revenue is recognized as services are delivered based on percentage-of-completion or milestone completion as defined in the contract. For product sales, revenue is recognized at the point of delivery when control transfers to the customer.\n\nNew contract types or non-standard arrangements must be reviewed by Finance and Legal before signing to ensure proper revenue recognition treatment is determined in advance. Variable consideration including bonuses, penalties, and refund rights must be estimated and constrained appropriately. Revenue recognition judgments are documented in the technical accounting log and reviewed quarterly with the external auditors.",
     "Revenue recognition policy following IFRS 15 covering subscription, professional services, and product revenue treatment.",
     "revenue recognition,ifrs,finance,accounting"),
    ("Finance", "Contract Review and Management Guide",
     "All commercial contracts entered into by the organization must go through a formal review and approval process before execution. Contract requests are submitted through the legal matter management system with the full contract document, counterparty details, and a business summary. Legal reviews for commercial and legal risk; Finance reviews for financial commitments and accounting implications.\n\nContracts are categorized by value and risk: Category 1 (routine, under $50,000) — standard template review by Legal; Category 2 ($50,000-$500,000) — full legal and finance review with manager approval; Category 3 (above $500,000 or high risk) — senior legal review, CFO approval, and CEO sign-off for contracts above $1M.\n\nExecuted contracts are stored in the contract management system with key metadata including counterparty, start date, end date, renewal terms, auto-renewal provisions, and key obligations. Automated alerts are sent at 90 and 30 days before expiry or renewal dates. Contract owners are responsible for monitoring performance obligations and flagging issues to Legal and Finance proactively.",
     "Contract review and management guide covering approval categories, review process, and contract lifecycle tracking.",
     "contracts,legal,finance,management"),
    ("Finance", "Insurance Claims Filing Process",
     "The Finance department manages the organization's insurance portfolio including property, liability, directors and officers, cyber, and employee health insurance. Incidents that may give rise to an insurance claim must be reported to Finance and Legal within 24 hours of the triggering event.\n\nTo file a claim, complete the Insurance Claim Notification Form available on the Finance intranet page with details of the incident, estimated financial impact, affected policies, and immediate mitigation actions taken. Finance will notify the relevant insurer and broker within 24 hours. An internal claim file is opened to track all related costs, correspondence, and legal documentation.\n\nDo not make admissions of liability or agree to settlements without prior approval from Legal and Finance. All claim-related communications with third parties must be routed through Legal. Finance tracks open claims in the claims register, which is reviewed quarterly with the insurance broker and at renewal to inform the following year's coverage and premium negotiations.",
     "Insurance claims filing process covering notification requirements, claim documentation, and communication protocols.",
     "insurance,claims,finance,risk management"),
    ("Finance", "Corporate Investment Policy",
     "The Corporate Investment Policy governs the management of the company's cash and short-term investment portfolio to preserve capital, maintain liquidity for operational needs, and achieve a competitive return within defined risk parameters. The Treasurer is responsible for day-to-day investment management within the bounds of this policy.\n\nPermitted investment instruments include bank deposits with A-rated institutions (maximum 12-month term), government securities (maximum 2-year maturity), money market funds with AAA ratings, and investment-grade corporate bonds (maximum 1-year maturity). Instruments not listed as permitted are not authorized without CFO and Board approval.\n\nConcentration limits apply: maximum 20% of total investable assets in any single institution and maximum 10% in any single corporate issuer. The investment portfolio is reviewed monthly by the Treasurer and quarterly by the CFO. Annual policy compliance certification is provided to the Audit Committee. Changes to the policy require Board approval.",
     "Corporate investment policy covering permitted instruments, concentration limits, and governance requirements for cash management.",
     "investment,treasury,finance,policy"),
    ("Finance", "Enterprise Financial Risk Management",
     "Enterprise Financial Risk Management (ERM) identifies, assesses, and mitigates risks that could materially impact the organization's financial position, reputation, or regulatory standing. Key risk categories include credit risk, liquidity risk, market risk (FX and interest rate), operational risk, and compliance risk.\n\nThe Risk Register is maintained by the Finance Risk function and updated quarterly. Each risk entry includes the risk description, likelihood and impact rating, inherent risk score, control description, residual risk score, risk owner, and treatment plan. Risks rated High or Critical trigger immediate escalation to the CFO and CISO.\n\nERM reporting is provided to the Audit Committee quarterly and the full Board semi-annually. Stress testing is conducted annually to assess the financial impact of extreme but plausible scenarios including economic downturn, cyber event, key supplier failure, and significant FX movement. Scenario analysis results inform contingency planning and capital adequacy assessments.",
     "Enterprise financial risk management framework covering risk categories, risk register maintenance, and Board-level reporting.",
     "risk management,finance,erm,governance"),

    # Operations (20)
    ("Operations", "IT Incident Management SOP",
     "The IT Incident Management Standard Operating Procedure defines the process for detecting, reporting, prioritizing, and resolving IT service incidents in a consistent and timely manner. An incident is any unplanned interruption to an IT service or a reduction in the quality of an IT service.\n\nIncidents are classified by priority based on urgency and impact: P1 (Critical — major service down), P2 (High — significant user impact), P3 (Medium — limited impact), P4 (Low — cosmetic or workaround available). P1 and P2 incidents require immediate assignment to an on-call engineer. P3 and P4 are queued in the IT Service Management system.\n\nThe incident lifecycle includes: Detection and Logging, Classification and Prioritization, Initial Diagnosis, Escalation if required, Investigation and Diagnosis, Resolution and Recovery, and Closure. Major incidents (P1) require a post-incident review within 5 business days. The review produces a root cause analysis and a set of preventative actions tracked in the Problem Management process.",
     "IT Incident Management SOP covering incident classification, priority levels, lifecycle stages, and post-incident review requirements.",
     "incident management,it operations,sop,itsm"),
    ("Operations", "Change Management Process Guide",
     "The Change Management process ensures that IT changes are assessed, approved, implemented, and reviewed in a controlled manner to minimize the risk of unplanned service disruptions. All changes to production infrastructure and applications must go through this process, regardless of size.\n\nChanges are categorized as Standard (pre-approved, low-risk, repeatable), Normal (requires CAB approval), or Emergency (urgent, requires CISO and CTO approval). Standard changes have a defined implementation procedure and do not require CAB review. Normal changes are reviewed at the weekly CAB meeting and must be submitted at least 5 business days prior. Emergency changes are logged within 2 hours of implementation and retroactively reviewed at the next CAB.\n\nEvery change must include a rollback plan and the estimated time to rollback if the change causes issues. Post-implementation review is mandatory for all Normal and Emergency changes and must be completed within 24 hours of implementation. Failed changes are analyzed in the Problem Management process. Change success rate is tracked as a KPI and reported to IT leadership monthly.",
     "Change management process guide covering change categories, CAB approval, rollback requirements, and post-implementation review.",
     "change management,it operations,itsm,process"),
    ("Operations", "Software Release Management Guide",
     "Software releases are managed through a structured release lifecycle to ensure quality, coordination, and controlled deployment to production environments. Releases are categorized as Major (significant new capabilities), Minor (smaller features and non-critical bug fixes), and Patch (security fixes and critical bug corrections).\n\nThe release calendar is published quarterly and all teams must register planned releases at least 6 weeks in advance for Major releases, 3 weeks for Minor, and 5 business days for Patches. Emergency patches may bypass the release calendar with CTO approval. All releases must pass the definition of ready criteria including completed feature testing, security scanning, performance baseline, and rollback plan documentation.\n\nRelease notes must be prepared and approved at least 48 hours before production deployment. Customer-facing release notes are published on the product portal. Internal release notes are distributed to the operations team, Help Desk, and customer success. Post-release monitoring is conducted for the first 4 hours after deployment, with the releasing team on standby for rapid response.",
     "Software release management guide covering release categories, calendar registration, release notes, and post-release monitoring.",
     "release management,software,devops,operations"),
    ("Operations", "Quality Assurance Standards Manual",
     "The Quality Assurance Standards Manual defines the minimum quality standards for all products and services delivered by the organization. Quality is defined across four dimensions: Functionality (meeting specified requirements), Reliability (consistent performance under defined conditions), Usability (ease of use for the intended user), and Performance (meeting speed, scalability, and efficiency requirements).\n\nAll software deliverables must meet the following testing standards before release: unit test coverage minimum 80%, integration tests covering all API contracts, end-to-end tests covering the top 5 user journeys, performance tests confirming sub-2-second response times for the 95th percentile, and security tests (SAST, DAST, and dependency scanning).\n\nQuality metrics including defect density, test coverage, and production incident rate are tracked on the Engineering Quality Dashboard. Quality gates are embedded in the CI/CD pipeline and block deployment when thresholds are breached. A monthly Quality Review meeting is held with engineering leads to analyze trends, identify systemic issues, and agree improvement actions.",
     "Quality assurance standards manual covering testing requirements, quality dimensions, metrics, and QA gates in the CI/CD pipeline.",
     "quality assurance,testing,standards,operations"),
    ("Operations", "Customer Escalation Handling Process",
     "Customer escalations are situations where a customer expresses dissatisfaction with the product or service received and requests resolution at a higher level of authority. Effective escalation handling is critical to customer retention, brand reputation, and the identification of systemic service delivery issues.\n\nEscalations are classified into three tiers: Tier 1 (frontline resolution within 24 hours), Tier 2 (escalated to Customer Success Manager within 4 hours of Tier 1 failure), Tier 3 (escalated to Director level for strategic accounts or persistent issues, response within 2 hours). All escalations must be logged in the CRM system within 30 minutes of identification.\n\nThe escalation handler is responsible for: acknowledging the customer within the tier SLA, providing regular status updates every 4 hours until resolution, proposing a resolution that addresses both the immediate issue and the root cause, and following up 5 days post-resolution to confirm satisfaction. Lessons learned from Tier 2 and Tier 3 escalations are reviewed in the weekly Customer Success team meeting.",
     "Customer escalation handling process covering tier classification, response SLAs, resolution ownership, and lessons learned review.",
     "customer escalation,operations,customer success,process"),
    ("Operations", "SLA Monitoring and Management Guide",
     "Service Level Agreements (SLAs) define the performance commitments made to internal and external customers for IT services. SLA management ensures that commitments are tracked, reported accurately, and that breaches are addressed proactively. SLA definitions are documented in the service catalog for each managed service.\n\nSLA metrics are captured by the monitoring platform in real-time and aggregated in the SLA Dashboard. The dashboard displays current-period performance, trend data for the last 6 months, and a heat map of services at risk of breaching their targets. Automated alerts are triggered when a service is within 10% of its SLA target threshold.\n\nSLA review meetings are held monthly with service owners and key stakeholders. Breached SLAs must have a root cause analysis and corrective action plan submitted within 5 business days. Credits or penalties triggered by SLA breaches are processed by Finance within 10 business days. Customer-facing SLA reports are distributed to account managers for inclusion in quarterly business reviews.",
     "SLA monitoring and management guide covering dashboard usage, breach alerts, corrective action plans, and reporting procedures.",
     "sla,monitoring,operations,service management"),
    ("Operations", "Third Party Vendor Management Policy",
     "Third-party vendors providing services that access company data or systems must undergo a formal vendor assessment before engagement. The assessment covers financial stability, information security posture, business continuity capability, and compliance certifications. Vendors are classified as Critical, High, Medium, or Low risk based on the assessment outcomes.\n\nAll vendors must sign the company's standard Master Services Agreement and Data Processing Agreement before commencing work. Variations to standard terms require Legal and Finance approval. Critical and High risk vendors are subject to annual reassessment and a site audit every 2 years. Contract renewal is contingent on satisfactory reassessment results.\n\nVendor performance is tracked through quarterly scorecards covering quality, timeliness, responsiveness, and compliance. Underperforming vendors receive a formal performance improvement notice. Vendor concentration risk is monitored quarterly to ensure no single vendor accounts for more than 30% of total external spend in any critical service category. A vendor exit plan is maintained for all Critical vendors.",
     "Third-party vendor management policy covering vendor assessment, contractual requirements, performance monitoring, and concentration risk.",
     "vendor management,third party,operations,policy"),
    ("Operations", "Business Continuity Planning Guide",
     "Business Continuity Planning (BCP) ensures the organization can maintain critical business functions during and after a major disruption. The BCP covers people, processes, technology, and facilities across all critical business units. The plan is reviewed annually and tested through desktop exercises every 6 months and a full simulation annually.\n\nEach business unit performs a Business Impact Analysis (BIA) annually to identify critical processes, maximum tolerable downtime, recovery time objectives, and minimum resource requirements. BIA results are used to prioritize recovery strategies and investment in resilience capabilities.\n\nThe BCP is structured in three phases: Response (first 2 hours — crisis activation, life safety, initial communications), Recovery (2-48 hours — alternate work arrangements, system recovery, stakeholder communications), and Restoration (48 hours+ — return to normal operations, lessons learned). Crisis command contacts and escalation trees are reviewed and updated quarterly to ensure accuracy.",
     "Business continuity planning guide covering BIA methodology, BCP phases, testing requirements, and crisis command structure.",
     "business continuity,bcp,operations,resilience"),
    ("Operations", "Enterprise Risk Assessment Framework",
     "The Enterprise Risk Assessment Framework provides a structured methodology for identifying, analyzing, evaluating, and treating risks across all business functions. Risk assessment is conducted at three levels: operational (individual processes), tactical (department/program), and strategic (organization-wide).\n\nThe risk assessment process follows five steps: Establish Context (scope and objectives), Risk Identification (structured brainstorming, process analysis, and historic incident review), Risk Analysis (likelihood and consequence scoring on a 5x5 matrix), Risk Evaluation (prioritization against risk appetite), and Risk Treatment (accept, avoid, mitigate, or transfer). Risk owners are assigned for all Medium, High, and Critical risks.\n\nRisk assessments are reviewed and refreshed annually or following significant organizational changes. The consolidated risk register is reviewed by the Risk Committee quarterly. Emerging risks identified outside the normal cycle are escalated through the fast-track risk review process. Risk management training for risk owners is provided biannually by the Risk function.",
     "Enterprise risk assessment framework covering the 5-step methodology, risk matrix, treatment options, and governance requirements.",
     "risk assessment,enterprise risk,operations,framework"),
    ("Operations", "Continuous Process Improvement Guide",
     "Continuous process improvement is embedded in the organization's operating model through a structured program that applies Lean and Six Sigma principles to identify waste, reduce variation, and enhance value delivery. All business units are expected to initiate at least two improvement projects per year.\n\nImprovement opportunities are identified through multiple channels: customer feedback, employee suggestions through the innovation portal, operational data analysis, and post-incident reviews. Ideas are evaluated using an effort/impact matrix and the top-ranked opportunities are formally scoped as improvement projects with a designated process owner.\n\nThe improvement methodology follows the DMAIC cycle: Define (problem statement and goals), Measure (baseline performance data), Analyze (root cause identification), Improve (solution design and piloting), and Control (standardization and monitoring). Projects must demonstrate measurable benefit — cost reduction, quality improvement, or customer satisfaction gain — and are reviewed at the monthly Operations Excellence meeting.",
     "Continuous process improvement guide covering the DMAIC methodology, opportunity identification, and project governance.",
     "process improvement,lean,six sigma,operations"),
    ("Operations", "Business Workflow Automation Guide",
     "Business workflow automation reduces manual effort, accelerates process cycle times, and improves data accuracy by eliminating human handoffs for routine, rules-based tasks. The organization uses Power Automate, ServiceNow Flow Designer, and n8n (for technical integrations) as the primary automation platforms.\n\nAutomation candidates must meet at least two of the following criteria: the process is performed more than 20 times per month, the process takes more than 15 minutes per instance, the process requires data transfer between two or more systems, or the process has a high rate of human error. Proposed automations are submitted to the Process Excellence team for feasibility review.\n\nAll automations are documented in the process automation register with business owner, process description, systems integrated, and expected benefits. Automations are tested in a non-production environment before deployment. Production automations are monitored for failures through alerting; any automation that fails is logged and the manual fallback process is activated. Automations are reviewed annually for continued relevance and accuracy.",
     "Business workflow automation guide covering platform standards, candidate criteria, documentation requirements, and monitoring.",
     "automation,workflow,operations,process"),
    ("Operations", "Management Reporting Standards",
     "Management reports provide the information that leaders need to make timely, evidence-based decisions. This document establishes the standards for management report design, content, distribution, and review to ensure consistency, reliability, and actionability across the organization.\n\nAll management reports must follow the SMART reporting principles: Specific (clearly defined metrics), Measurable (quantified with data), Actionable (focused on decision-relevant information), Relevant (aligned with strategic objectives), and Timely (published within defined SLAs). Reports must include a forward-looking commentary, not just historical data.\n\nStandard report templates are maintained in SharePoint and must be used for all recurring management reports. New report requests must be submitted to the FP&A team with a business case. The report catalog is reviewed annually to decommission obsolete reports. Access to management reports is controlled through SharePoint permissions based on role; report distribution via email to external parties is prohibited without Finance Director approval.",
     "Management reporting standards covering design principles, SMART criteria, template usage, and access control requirements.",
     "management reporting,operations,standards,analytics"),
    ("Operations", "Effective Meeting Management Guidelines",
     "Well-managed meetings are a multiplier of organizational effectiveness; poorly managed meetings are one of the largest sources of wasted time. These guidelines apply to all recurring and ad-hoc meetings in the organization and are designed to maximize meeting value and minimize participants' time investment.\n\nBefore scheduling a meeting, consider whether the objective can be achieved asynchronously through a document, email, or Slack message. If a meeting is necessary, limit attendance to decision-makers and essential contributors. Every meeting must have a clear agenda sent at least 24 hours in advance, with the expected outcome for each agenda item (decision, input, or information).\n\nDuring the meeting, start and end on time, assign a note-taker, and capture decisions and action items with owners and due dates in real-time. Follow up with a written summary within 24 hours of the meeting. Recurring meetings should be reviewed every quarter and cancelled if they consistently run without decisions or actions. Cameras-on is the standard for video meetings with 5 or fewer participants.",
     "Meeting management guidelines covering pre-meeting requirements, facilitation standards, and post-meeting follow-up procedures.",
     "meetings,operations,productivity,guidelines"),
    ("Operations", "Technical Documentation Standards",
     "Technical documentation provides the knowledge foundation for building, operating, and maintaining systems reliably. High-quality documentation reduces onboarding time, improves incident response, and enables knowledge continuity during team changes. These standards apply to all technical documentation produced by engineering and operations teams.\n\nRequired documentation types for all production services include: Architecture Decision Record (ADR), System runbook, API documentation (OpenAPI spec), Deployment guide, Data flow diagram, and Security threat model. Documentation is maintained in Confluence under the relevant team's space. Each document has a designated owner responsible for accuracy.\n\nDocumentation quality is reviewed quarterly using the Documentation Health Score, which checks for completeness, accuracy (no stale sections older than 6 months), and accessibility (findable via Confluence search). Documentation debt identified in the health score is tracked as a team engineering objective. New services cannot be promoted to production without completing the minimum required documentation.",
     "Technical documentation standards covering required document types, Confluence organization, and documentation health score reviews.",
     "documentation,technical writing,standards,operations"),
    ("Operations", "OKR and KPI Tracking Process",
     "Objectives and Key Results (OKRs) are used to set and align organizational goals at company, department, and team levels. Key Performance Indicators (KPIs) are used to track ongoing operational performance against targets. Together, OKRs and KPIs provide a balanced view of strategic progress and operational health.\n\nThe annual OKR cycle begins in November when the executive team sets company-level Objectives. Departments cascade their OKRs from the company objectives by December 15th. Team-level OKRs are finalized by January 10th. OKR progress is reviewed in monthly check-ins at the team level and in quarterly business reviews at the company level.\n\nKPIs are reviewed in the Operations Dashboard, which is updated weekly. Each KPI has a defined target, amber threshold, and red threshold. KPIs in the red zone for two consecutive weeks require a documented corrective action plan. The Operations Excellence team facilitates the quarterly OKR retrospective, where teams grade their results, identify learnings, and feed inputs into the next OKR cycle.",
     "OKR and KPI tracking process covering goal-setting cycles, review cadences, dashboard management, and corrective action protocols.",
     "okr,kpi,operations,goals"),
    ("Operations", "Customer Feedback Collection Process",
     "Collecting and acting on customer feedback is fundamental to delivering a continuously improving product and service experience. Feedback is collected through multiple channels at key moments in the customer journey: post-purchase surveys, quarterly relationship surveys, support ticket satisfaction ratings, and quarterly executive business reviews.\n\nAll feedback data flows into the Voice of Customer (VoC) platform, which aggregates scores, identifies trends, and generates alerts for at-risk accounts. Net Promoter Score (NPS) is the primary relationship health metric, measured quarterly for all accounts. Customer Satisfaction Score (CSAT) is measured after every support interaction. Product Experience scores are gathered in-app through micro-surveys.\n\nFeedback is reviewed weekly by Customer Success teams and monthly in the cross-functional Customer Experience Council. Closed-loop follow-up with customers who provide low scores is completed within 5 business days. Product feedback is triaged weekly by Product Management and high-frequency themes are incorporated into the product roadmap. Improvements driven by customer feedback are communicated back to customers through the product newsletter.",
     "Customer feedback collection process covering survey cadences, VoC platform usage, NPS tracking, and closed-loop follow-up.",
     "customer feedback,nps,operations,customer success"),
    ("Operations", "Resource Allocation and Planning Guide",
     "Effective resource allocation ensures that the right people and materials are deployed to the highest-priority activities while maintaining the capacity to respond to unplanned demands. Resource planning is conducted at three horizons: strategic (12+ months), tactical (1-3 months), and operational (current week).\n\nResource demand is captured through the project portfolio management tool, where all projects must register their resource requirements by role, skill level, and time period. Resource supply is managed through the capacity management process, which tracks current allocation, upcoming availability, and skill coverage. Resource conflicts are escalated to the Resource Management Committee for prioritization decisions.\n\nWhen demand exceeds supply for critical skills, options assessed in order include: internal reallocation from lower-priority work, temporary increase in contractor headcount, hiring permanent staff with a lead time of 3 months, or descoping or deferring the project. Resource utilization targets are set at 80% for billable roles (allowing for overhead and unplanned work) and 70% for support roles.",
     "Resource allocation and planning guide covering demand capture, capacity management, conflict escalation, and utilization targets.",
     "resource planning,capacity,operations,project management"),
    ("Operations", "Project Closure and Handover Process",
     "Project closure is the final phase of the project lifecycle and ensures that deliverables are formally accepted, documentation is complete, lessons are captured, and the project is officially closed. Skipping the closure phase leads to knowledge loss, unclear ownership, and ongoing costs for resources that should be released.\n\nThe closure checklist includes: stakeholder sign-off on all deliverables, handover of operational runbooks and documentation to the support team, transfer of project artifacts to the relevant archive in SharePoint, financial closure (final costs reconciled against budget, any remaining PO balances cancelled), resource releases processed in the project portfolio tool, and team recognition event.\n\nA closure report summarizing objectives, outcomes, budget variance, schedule variance, lessons learned, and recommendations for future projects is prepared by the Project Manager and submitted to the project sponsor within 10 business days of final delivery. The PMO reviews closure reports quarterly to identify patterns and update project management standards and templates.",
     "Project closure and handover process covering the closure checklist, documentation requirements, and post-project closure report.",
     "project closure,handover,operations,project management"),
    ("Operations", "Stakeholder Communication Plan Template",
     "A stakeholder communication plan defines who needs to receive what information, how frequently, through which channel, and with what level of detail throughout a project or initiative. An effective communication plan prevents misalignment, builds stakeholder confidence, and ensures decision-makers have timely information.\n\nThe communication plan template includes columns for: Stakeholder Name, Role, Interest Level (High/Medium/Low), Influence Level (High/Medium/Low), Information Needed, Communication Method, Frequency, Owner, and Last Updated. Stakeholders are segmented into groups by role type (Executive, Operational, Technical, Customer) to enable efficient communication management.\n\nThe plan is completed during project initiation and reviewed at each phase gate. Communication effectiveness is assessed at project retrospectives through stakeholder feedback. Gaps identified in retrospectives are used to update the template for future projects. For large programs, a dedicated Communications Manager is assigned to own the plan and execution.",
     "Stakeholder communication plan template covering stakeholder segmentation, communication methods, frequency, and effectiveness review.",
     "stakeholder communication,operations,project management,template"),
    ("Operations", "Business Performance Metrics Guide",
     "The Business Performance Metrics Guide establishes the standard set of metrics used to assess organizational performance across Financial, Customer, Operational, and People dimensions in alignment with the Balanced Scorecard framework. Consistent metric definitions ensure comparability across business units and over time.\n\nFinancial metrics include Revenue Growth Rate, Gross Margin, Operating Expense Ratio, Cash Conversion Cycle, and Return on Invested Capital. Customer metrics include NPS, Customer Retention Rate, Customer Lifetime Value, and Time to Resolution. Operational metrics include Process Cycle Time, First Time Right Rate, SLA Attainment, and System Uptime. People metrics include Employee Engagement Score, Voluntary Turnover Rate, and Time to Full Productivity.\n\nMetric definitions, calculation methodologies, data sources, and reporting owners are documented in the Metric Glossary maintained by the FP&A team. Changes to metric definitions must be approved by the CFO and communicated to all reporting owners at least one full reporting period before taking effect. Historical data is restated when definition changes are retroactively applicable.",
     "Business performance metrics guide covering the Balanced Scorecard framework, metric definitions, and governance for metric changes.",
     "performance metrics,balanced scorecard,operations,analytics"),
]


def _write_json(records, output_path):
    with open(output_path, "w", encoding="utf-8") as f:
        import json
        json.dump({"articles": records}, f, indent=2, ensure_ascii=False)


def generate_sample_csv(output_path: str, count: int = 120):
    os.makedirs(os.path.dirname(output_path) if os.path.dirname(output_path) else ".", exist_ok=True)

    start_date = date(2023, 1, 1)
    end_date = date(2024, 12, 31)
    total_days = (end_date - start_date).days
    step = total_days // count

    rows = []
    for i, (category, title, content, summary, tags) in enumerate(ARTICLES[:count]):
        if i < 96:
            status = "approved"
        elif i < 108:
            status = "pending"
        else:
            status = "draft"

        author_email = "author@ekbms.com" if i % 2 == 0 else "admin@ekbms.com"
        views = random.randint(50, 2500)
        created_at = (start_date + timedelta(days=i * step)).strftime("%Y-%m-%d")

        rows.append({
            "title": title,
            "content": content,
            "summary": summary,
            "category": category,
            "tags": tags,
            "author_email": author_email,
            "views": views,
            "status": status,
            "created_at": created_at,
        })

    fieldnames = ["title", "content", "summary", "category", "tags", "author_email", "views", "status", "created_at"]
    with open(output_path, "w", newline="", encoding="utf-8") as f:
        writer = csv.DictWriter(f, fieldnames=fieldnames)
        writer.writeheader()
        writer.writerows(rows)

    json_path = output_path.replace(".csv", ".json")
    _write_json(rows, json_path)

    print(f"Generated {count} articles -> {output_path}")
    return output_path, json_path


if __name__ == "__main__":
    generate_sample_csv("sample_data/articles.csv", 120)
